// Package workerstatus reports on live "ddx work" / "ddx try" processes,
// scoped to a specific project root by default.
//
// Operators and agents asking "is the worker still working beads?" must be
// able to answer the question for one project at a time. A global process
// scan ("ps aux | grep ddx work") returns workers from every checkout on the
// machine and produces a misleading "yes, working" signal when the worker
// belongs to a different repository. This package filters live workers by
// the resolved project root so the answer always matches the question.
package workerstatus

import (
	"context"
	"path/filepath"
	"regexp"
	"strings"
	"time"
)

// LiveWorker describes one running ddx worker process.
type LiveWorker struct {
	PID                int             `json:"pid"`
	Command            string          `json:"command"`
	StartedAt          time.Time       `json:"started_at"`
	AgeSeconds         float64         `json:"age_seconds"`
	Age                string          `json:"age"`
	ProjectRoot        string          `json:"project_root"`
	BeadID             string          `json:"bead_id,omitempty"`
	AttemptID          string          `json:"attempt_id,omitempty"`
	Phase              string          `json:"phase,omitempty"`
	Message            string          `json:"message,omitempty"`
	ChildPID           int             `json:"child_pid,omitempty"`
	LastActivityAt     time.Time       `json:"last_activity_at,omitempty"`
	ExecutionWorktree  string          `json:"execution_worktree,omitempty"`
	Cwd                string          `json:"cwd,omitempty"`
	ProviderChildren   []ProviderChild `json:"provider_children,omitempty"`
	StaleMonitorShells int             `json:"stale_monitor_shells,omitempty"`
}

// ProviderChild describes a provider CLI subprocess observed under a worker.
//
// RouteOwner is set when the child's provider matches the worker's active
// route/harness; such a child is legitimate route work and is never reaped.
// NonRoute is set on a provider CLI whose provider does not match the active
// route — an unrelated harness the running-phase guard terminates — and
// Diagnostic carries an operator-facing explanation for that quarantine.
type ProviderChild struct {
	PID        int     `json:"pid"`
	Provider   string  `json:"provider"`
	Harness    string  `json:"harness,omitempty"`
	RouteOwner string  `json:"route_owner,omitempty"`
	Phase      string  `json:"phase,omitempty"`
	AgeSeconds float64 `json:"age_seconds"`
	NonRoute   bool    `json:"non_route,omitempty"`
	Diagnostic string  `json:"diagnostic,omitempty"`
}

// Scanner discovers live ddx worker processes on the host.
type Scanner interface {
	Scan(ctx context.Context) ([]LiveWorker, error)
}

// New returns the platform-appropriate Scanner. On Linux this reads /proc.
// On other platforms it returns an empty list; the caller's tests and the
// --all-projects escape hatch remain meaningful regardless.
func New() Scanner {
	return newSystemScanner()
}

// beadIDPattern matches ddx-style bead identifiers (prefix + hex, 8+ chars
// total) embedded in argv strings or worktree paths.
var beadIDPattern = regexp.MustCompile(`\bddx-[a-f0-9]{8}\b`)

// executionWorktreePattern matches the conventional execute-bead worktree
// directory name (`.execute-bead-wt-<bead>-<timestamp>-<suffix>`) anywhere
// in a path. The directory name is enough to identify the worktree even when
// the surrounding path is unconventional.
var executionWorktreePattern = regexp.MustCompile(`(?:^|/)(\.execute-bead-wt-[^/]+)`)

// InferBead extracts a bead ID and execution worktree path from the worker's
// command line and current working directory. It returns the longest worktree
// path that contains a `.execute-bead-wt-*` segment (typically the cwd, when
// the inline worker has chdir'd into the isolated worktree), and the first
// bead ID matched in either the command line or the worktree path.
//
// Either return value may be empty when no signal is present, which is the
// expected case for a long-running `ddx work` drain that has not yet started
// a specific bead.
func InferBead(cmdline, cwd string) (beadID, worktree string) {
	worktree = extractWorktreePath(cwd)
	if worktree == "" {
		worktree = extractWorktreePath(cmdline)
	}

	if m := beadIDPattern.FindString(worktree); m != "" {
		beadID = m
	}
	if beadID == "" {
		if m := beadIDPattern.FindString(cmdline); m != "" {
			beadID = m
		}
	}
	if beadID == "" {
		if m := beadIDPattern.FindString(cwd); m != "" {
			beadID = m
		}
	}
	return beadID, worktree
}

func extractWorktreePath(s string) string {
	if s == "" {
		return ""
	}
	if !strings.Contains(s, ".execute-bead-wt-") {
		return ""
	}
	matches := executionWorktreePattern.FindStringIndex(s)
	if matches == nil {
		return ""
	}
	start := matches[0]
	end := matches[1]
	for start > 0 {
		r := s[start-1]
		if r == ' ' || r == '\x00' || r == '\t' {
			break
		}
		start--
	}
	for end < len(s) {
		r := s[end]
		if r == ' ' || r == '\x00' || r == '\t' {
			break
		}
		end++
	}
	return s[start:end]
}

// FilterByProject returns workers whose ProjectRoot resolves to the same path
// as projectRoot. Resolution canonicalises both sides via filepath.Abs and
// filepath.EvalSymlinks so a symlinked checkout matches its real path.
func FilterByProject(workers []LiveWorker, projectRoot string) []LiveWorker {
	target := canonicalPath(projectRoot)
	out := make([]LiveWorker, 0, len(workers))
	for _, w := range workers {
		if SamePath(w.ProjectRoot, target) {
			out = append(out, w)
		}
	}
	return out
}

// SamePath reports whether a and b refer to the same on-disk location after
// canonicalisation. It tolerates empty inputs (returning false) so callers
// can safely compare optional fields without prefiltering.
func SamePath(a, b string) bool {
	ca := canonicalPath(a)
	cb := canonicalPath(b)
	if ca == "" || cb == "" {
		return false
	}
	return ca == cb
}

func canonicalPath(p string) string {
	if strings.TrimSpace(p) == "" {
		return ""
	}
	abs, err := filepath.Abs(p)
	if err != nil {
		abs = filepath.Clean(p)
	}
	if resolved, err := filepath.EvalSymlinks(abs); err == nil {
		return resolved
	}
	return abs
}

// FormatAge renders a duration as a short human-readable string mirroring
// the conventions used by the server-backed worker list (`5s`, `12m`,
// `1h30m`). It is intended for terminal output; JSON output uses
// AgeSeconds as the numeric source of truth.
func FormatAge(d time.Duration) string {
	if d < time.Minute {
		if d < 0 {
			d = 0
		}
		return roundedSeconds(d)
	}
	if d < time.Hour {
		return roundedMinutes(d)
	}
	hours := int(d.Hours())
	mins := int(d.Minutes()) % 60
	if mins == 0 {
		return durationHours(hours)
	}
	return durationHoursMinutes(hours, mins)
}

func roundedSeconds(d time.Duration) string {
	secs := int(d.Seconds())
	return durationSeconds(secs)
}

func roundedMinutes(d time.Duration) string {
	mins := int(d.Minutes())
	return durationMinutes(mins)
}

func durationSeconds(n int) string { return formatUnit(n, "s") }
func durationMinutes(n int) string { return formatUnit(n, "m") }
func durationHours(n int) string   { return formatUnit(n, "h") }
func durationHoursMinutes(h, m int) string {
	return formatUnit(h, "h") + formatUnit(m, "m")
}

func formatUnit(n int, unit string) string {

package cmd

import (
	"encoding/json"
	"fmt"
	"io"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	workguard "github.com/DocumentDrivenDX/ddx/internal/agent/work"
	"github.com/DocumentDrivenDX/ddx/internal/escalation"
	"github.com/DocumentDrivenDX/ddx/internal/lockmetrics"
	"github.com/spf13/cobra"
)

// newWorkCommand creates the top-level "ddx work" command: the FEAT-010 layer-3
// queue drain. ddx work treats --harness,
// --provider, and --model as opaque passthrough constraints that are forwarded
// to the agent unchanged. DDx does not validate or branch on their values.
// Retry-power policy between attempts is owned here, not in the agent service.
func (f *CommandFactory) newWorkCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:           "work",
		Short:         "Drain the bead execution queue",
		SilenceUsage:  true,
		SilenceErrors: true,
		Long: `work drains the execution-ready bead queue. It is the FEAT-010 layer-3
queue drain: it iterates ddx try (layer 2) across ready beads until a stop
condition is met and owns retry-power policy between attempts.

ddx work treats --harness, --provider, --model, and --profile as opaque
passthrough constraints forwarded to Fizeau unchanged. DDx does not validate
these values or branch on them; Fizeau owns routing within the requested power
bounds.

Review is on by default. --no-review is a break-glass override and
requires --no-review-i-know-what-im-doing. A bead label of review:skip
is only honored when it also carries a sibling review:skip-reason:*
label; otherwise the label is ignored.

Stop conditions (evaluated between attempts):
  drained     — no ready beads remain
  blocked     — every remaining bead has produced a terminal non-success outcome
  deferred    — configured budget exhausted
  no_progress — N consecutive attempts produced no commit (default N=3)
  signal      — SIGINT/SIGTERM received between attempts

work runs inline in the current process; per ADR-022 there is no separate
"submit to server" mode. The legacy --local flag is accepted but ignored
(deprecation warning printed) and will be removed in a future release.
`,
		Example: `  # Drain the current execution-ready queue and exit
  ddx work

  # Pick one ready bead, execute it, and stop
  ddx work --once

  # Watch for newly-ready work after the current queue drains
  ddx work --watch

  # Watch with a shorter idle scan interval
  ddx work --watch --idle-interval 15s

  # Forward harness/model as passthrough constraints (ddx does not validate these)
  ddx work --once --harness agent --model minimax/minimax-m2.7

  # Skip review only with the break-glass acknowledgement flag
  ddx work --once --no-review --no-review-i-know-what-im-doing

  # Constrain power powerClass (retry-power policy is owned by ddx work)
  ddx work --once --min-power 40 --max-power 90`,
		Args: cobra.NoArgs,
		RunE: f.runWork,
	}

	// Routing knobs — passthrough only. ddx work forwards these to the agent
	// unchanged and does not validate or branch on their string values.
	cmd.Flags().String("project", "", "Target project root path or name (default: CWD git root). Env: DDX_PROJECT_ROOT")
	cmd.Flags().String("from", "", "Base git revision to start from (default: HEAD)")
	cmd.Flags().String("harness", "", "Agent harness constraint (passthrough; ddx work does not validate)")
	cmd.Flags().String("model", "", "Model constraint (passthrough; ddx work does not validate)")
	cmd.Flags().String("profile", "", "Routing profile: default, cheap, fast, or smart (empty = unconstrained; let the agent service choose)")
	cmd.Flags().String("provider", "", "Provider constraint (passthrough; ddx work does not validate)")
	cmd.Flags().String("effort", "", "Effort level")
	cmd.Flags().String("attempt-backend", "", "Attempt backend: worktree, local-clone, docker-clone, or in-tree (default: executions.attempt_backend)")
	cmd.Flags().Bool("ignore-cooldown", false, "Ignore retry cooldown across this worker session (requires --reason)")
	cmd.Flags().String("reason", "", "Operator reason required by --ignore-cooldown")
	cmd.Flags().Bool("once", false, "Process at most one ready bead")
	cmd.Flags().Bool("watch", false, "Keep watching for newly-ready beads after the current queue drains")
	cmd.Flags().Bool("self-refresh", false, "Force re-exec onto a newer installed ddx binary between iterations (on by default in watch mode; use --no-self-refresh to disable)")
	cmd.Flags().Bool("no-self-refresh", false, "Disable self-refresh: do NOT re-exec onto a newer installed ddx binary between watch iterations (self-refresh is on by default in watch mode)")
	cmd.Flags().Duration("idle-interval", 30*time.Second, "Sleep duration between empty-queue scans in watch mode")
	cmd.Flags().Bool("json", false, "Output loop result as JSON")
	cmd.Flags().Bool("local", false, "Deprecated: no-op; ddx work always runs inline (ADR-022)")
	_ = cmd.Flags().MarkDeprecated("local", "ddx work always runs inline; the flag is a no-op (ADR-022)")
	cmd.Flags().Bool("no-review", false, "Skip post-merge review (break-glass: requires --no-review-i-know-what-im-doing)")
	cmd.Flags().Bool("no-review-i-know-what-im-doing", false, "Break-glass acknowledgement required when using --no-review")
	cmd.Flags().String("review-harness", "", "Harness for the post-merge reviewer (default: same as implementation harness)")
	cmd.Flags().String("review-model", "", "Model override for the post-merge reviewer (default: smart powerClass)")
	cmd.Flags().Float64("max-cost", escalation.DefaultMaxCostUSD, "Stop when accumulated billed cost exceeds USD; 0 = unlimited")
	cmd.Flags().Float64("max-bead-cost", escalation.DefaultMaxBeadCostUSD, "Per-bead cost budget in USD; stop escalating when this bead's billed cost exceeds this amount (0 = unlimited); overridden per-bead by a budget:<USD> label")
	cmd.Flags().Float64("max-recovery-cost", escalation.DefaultMaxRecoveryCostUSD, "Per-bead automated recovery budget in USD for reframe/decompose attempts after repeated ladder exhaustion")
	cmd.Flags().Int("claim-rate-window", agent.DefaultClaimSuccessRateWindow, "Rolling window of recent claim attempts used to compute the claim success rate warning")
	cmd.Flags().Float64("claim-rate-threshold", agent.DefaultClaimSuccessRateThreshold, "Warn when the rolling claim success rate over a full window is at or below this threshold")
	cmd.Flags().Int("preclaim-warn-threshold", agent.DefaultPreClaimWarnRepeatThreshold, "Consecutive identical pre-claim warn fingerprints across distinct bead IDs required before the loop emits operator attention")
	cmd.Flags().Duration("preclaim-timeout", workguard.DefaultPreClaimTimeout, "Pre-claim readiness timeout for preflight/readiness hooks")
	cmd.Flags().Duration("route-resolution-timeout", agent.DefaultRouteResolutionTimeout, "Timeout bounding routing preflight and the resolveRoute viability check; on expiry the lease is released and the bead is flagged for operator attention")
	cmd.Flags().Duration("request-timeout", 0, "Per-request provider wall-clock timeout; overrides project config and model-class defaults")
	// Per-bead rate-limit retry budget (ddx-c6e3db02 / TD-031 §8.4).
	cmd.Flags().Duration("rate-limit-max-wait", agent.RateLimitRetryDefaultBudget,
		"Per-bead total wait budget for HTTP 429 / rate-limit retries (default 5m). 0 keeps the default; negative disables retry.")
	// Power bounds: ddx work owns retry-power policy — these set the envelope
	// for operator-constrained power within which the agent selects the route.
	cmd.Flags().Int("min-power", 0, "Minimum model power required (0 = unconstrained); passed to agent routing unchanged")
	cmd.Flags().Int("max-power", 0, "Maximum model power allowed (0 = unconstrained); passed to agent routing unchanged")

	// Register "ddx work plan", "ddx work focus", "ddx work clear-cooldowns",
	// "ddx work metrics", "ddx work analyze", and "ddx work status" as
	// subcommands.
	cmd.AddCommand(f.newWorkPlanCommand())
	cmd.AddCommand(f.newWorkFocusCommand())
	cmd.AddCommand(f.newWorkClearCooldownsCommand())
	cmd.AddCommand(f.newWorkMetricsCommand())
	cmd.AddCommand(f.newWorkAnalyzeCommand())
	cmd.AddCommand(f.newWorkStatusCommand())

	return cmd
}

// runWork is the RunE for "ddx work". It drives the FEAT-010 layer-3 queue
// drain with harness/provider/model treated as opaque passthrough constraints —
// ValidateForExecuteLoopViaService is not called; DDx does not inspect or
// branch on those values. Retry-power policy (min-power / max-power) is owned
// by this layer.
func (f *CommandFactory) runWork(cmd *cobra.Command, args []string) error {
	if err := f.checkLifecycleMigrationGate(cmd); err != nil {
		return err
	}

	projectFlag, _ := cmd.Flags().GetString("project")
	projectRoot := resolveProjectRoot(projectFlag, f.WorkingDir)
	lockmetrics.SetSink(lockmetrics.FileSink(projectRoot))
	lockmetrics.SetCapEnforcement(projectRoot, "")
	f.warnIfInstalledBinaryBehindSource(cmd)

	// Preflight: warn once per process for degraded project-local skill layout.
	// Suppressed in JSON mode to avoid corrupting machine-readable output
	// (stderr and stdout are merged by some test helpers and log aggregators).
	asJSON, _ := cmd.Flags().GetBool("json")
	if !asJSON {
		preflightResult := checkProjectRuntimePreflight(projectRoot)
		f.preflightWarnOnce.Do(func() {
			emitPreflightWarning(cmd.ErrOrStderr(), preflightResult)
		})
	}

	return f.runAgentExecuteLoopImpl(cmd, true, "")
}

func writeExecuteLoopResult(w io.Writer, projectRoot string, result *agent.ExecuteBeadLoopResult, asJSON bool) error {
	if asJSON {
		payload := struct {
			ProjectRoot string `json:"project_root"`
			*agent.ExecuteBeadLoopResult
		}{
			ProjectRoot:           projectRoot,
			ExecuteBeadLoopResult: result,
		}
		enc := json.NewEncoder(w)
		enc.SetIndent("", "  ")
		return enc.Encode(payload)
	}

	if result.NoReadyWork && result.Attempts == 0 {
		writeNoReadyWorkSummary(w, projectRoot, result.NoReadyWorkDetail)
		writeQueueSnapshotTerminalSummary(w, result.QueueSnapshot)
		return nil
	}

	fmt.Fprintf(w, "\nproject: %s\n", projectRoot)
	writeWorkTerminalSummary(w, result)
	writeOperatorAttentionSummary(w, result.OperatorAttention)
	preserved := preservedWorkAttempts(result)
	if len(preserved) > 0 {
		fmt.Fprintf(w, "\npreserved:\n")
		for _, attempt := range preserved {
			fmt.Fprintf(w, "  - %s: %s", attempt.BeadID, attempt.Detail)
			if attempt.PreserveRef != "" {
				fmt.Fprintf(w, " (%s)", attempt.PreserveRef)
			}
			fmt.Fprintln(w)
		}
	}
	failed := failedWorkAttempts(result)
	if len(failed) > 0 {
		fmt.Fprintf(w, "\nfailed:\n")
		for _, attempt := range failed {
			fmt.Fprintf(w, "  - %s: %s", attempt.BeadID, attempt.Detail)
			if attempt.PreserveRef != "" {
				fmt.Fprintf(w, " (preserved)")
			}
			fmt.Fprintln(w)
		}
	}
	if result.NoReadyWork {
		fmt.Fprintln(w)
		writeNoReadyWorkSummary(w, "", result.NoReadyWorkDetail)
		writeQueueSnapshotTerminalSummary(w, result.QueueSnapshot)
	}
	return nil
}

func writeWorkTerminalSummary(w io.Writer, result *agent.ExecuteBeadLoopResult) {
	closed, changed, alreadySatisfied, preserved := countWorkTerminalOutcomes(result)
	fmt.Fprintf(w, "worker exited: %s\n", workExitSummary(result))
	fmt.Fprintf(w, "attempts: %d  |  closed: %d  |  changed: %d  |  already-satisfied: %d  |  preserved: %d  |  failures: %d\n",
		result.Attempts, closed, changed, alreadySatisfied, preserved, result.Failures)
}

func writeOperatorAttentionSummary(w io.Writer, stop *agent.OperatorAttentionStop) {
	if stop == nil {
		return
	}
	fmt.Fprintln(w)
	fmt.Fprintln(w, "operator attention:")
	if stop.BeadID != "" {
		fmt.Fprintf(w, "  released bead: %s\n", stop.BeadID)
	}
	if stop.Message != "" {
		fmt.Fprintf(w, "  %s\n", stop.Message)
	}
	if stop.ProjectRoot != "" {
		fmt.Fprintf(w, "  project root: %s\n", stop.ProjectRoot)
	}
	if len(stop.DirtyPaths) > 0 {
		fmt.Fprintf(w, "  dirty paths: %s\n", strings.Join(stop.DirtyPaths, ", "))
	}
}

package agent

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"os"
	"path/filepath"
	"regexp"
	"sort"
	"strings"
	"sync"
	"time"

	agentlib "github.com/easel/fizeau"

	"github.com/DocumentDrivenDX/ddx/internal/agent/executeloop"
	agenttry "github.com/DocumentDrivenDX/ddx/internal/agent/try"
	"github.com/DocumentDrivenDX/ddx/internal/agent/work"
	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	"github.com/DocumentDrivenDX/ddx/internal/escalation"
	"github.com/DocumentDrivenDX/ddx/internal/evidence"
	"github.com/DocumentDrivenDX/ddx/internal/gitlock"
	"github.com/DocumentDrivenDX/ddx/internal/trackerpaths"
	"github.com/DocumentDrivenDX/ddx/internal/workerstatus"
)

const serverUnavailableLogMessage = "server unreachable: holding queue until /api/health returns"
const serverUnavailableStatePhase = "server.unavailable"

// ExecuteBeadLoopRuntime carries the non-serializable plumbing and
// per-invocation runtime intent for an execute-bead loop run. Durable knobs
// (assignee, retry caps, harness/model, powerClass bounds, etc.) live on
// config.ResolvedConfig and are passed via Run's rcfg argument.
type ExecuteBeadLoopRuntime struct {
	Log             io.Writer
	CleanupLog      io.Writer
	CleanupRunner   executionCleanupRunner
	ResourceChecker ExecutionResourceChecker
	CleanupInterval time.Duration
	CleanupTickCh   <-chan time.Time
	EventSink       io.Writer
	ProgressCh      chan<- ProgressEvent
	PreClaimHook    func(ctx context.Context) error
	// PreClaimIntakeHook runs after routing preflight and before Claim. It
	// classifies the candidate for actionability/scope; only
	// actionable_atomic proceeds directly to Claim. Non-atomic outcomes
	// skip the bead without claim. intake_error fail-opens so infrastructure
	// failures do not become hidden dispatch failures.
	PreClaimIntakeHook    PreClaimIntakeHook
	PreDispatchLintHook   func(ctx context.Context, beadID string) (LintResult, error)
	PostAttemptTriageHook func(ctx context.Context, beadID string, report ExecuteBeadReport) (TriageResult, error)
	// ProseEvidenceHook runs after a successful (landed) attempt and before
	// CloseWithEvidence so docs-changing attempts attach advisory prose-check
	// evidence to the bead's event history. Errors are logged and ignored;
	// prose findings never block closure.
	ProseEvidenceHook ProseEvidenceHook
	// PostAttemptDecompositionHook is called when a no_changes attempt signals
	// orchestrator_action: decompose in its rationale, indicating the bead is too
	// large for implementation-level splitting. The hook should run the same
	// orchestrator splitter used by the intake gate and return child specs and an
	// AC map. A nil return or error falls back to operator-required parking.
	PostAttemptDecompositionHook func(ctx context.Context, beadID string) (*PreClaimDecomposition, error)
	// ReviewCostCap, when non-nil, accumulates reviewer cost on the same
	// loop budget tracker used by the implementer attempts.
	ReviewCostCap *escalation.CostCapTracker
	// RoutePreflight, when non-nil, runs once during Run bootstrap before
	// the drain loop starts. It is expected to call upstream ResolveRoute
	// against the loop's resolved (harness, model) and return whatever typed
	// routing error the upstream surfaced — notably
	// agent.ErrHarnessModelIncompatible when the harness allow-list rejects
	// the model. Any non-nil error stops the worker before any bead is
	// claimed; DDx does NOT duplicate the upstream allow-list.
	RoutePreflight func(ctx context.Context, harness, model string) error
	// PreClaimTimeout bounds the pre-claim readiness hooks. Zero means use the
	// binary default so a hanging readiness check cannot park the worker
	// forever.
	PreClaimTimeout time.Duration
	// PreClaimWarnRepeatThreshold is the number of consecutive pre-claim warn
	// fingerprints across distinct bead IDs that trips the operator-attention
	// guard. Zero means use DefaultPreClaimWarnRepeatThreshold.
	PreClaimWarnRepeatThreshold int
	// RouteResolutionTimeout bounds the routing preflight (RoutePreflight) and
	// the resolveRoute viability check so a hung resolver cannot wedge the
	// single-threaded worker for hours while a lease is held (ddx-8f2e0ebf).
	// Zero means use DefaultRouteResolutionTimeout (60s).
	RouteResolutionTimeout time.Duration
	// ConsecutiveWedgeThreshold is the number of consecutive wedges
	// (route_resolution_timeout / progress_watchdog) on the same bead that
	// trips the consecutive-wedge guard: the worker stops re-claiming the bead
	// and parks it for operator attention. Zero means use
	// DefaultConsecutiveWedgeThreshold (2) (ddx-9714eaac).
	ConsecutiveWedgeThreshold int
	// ClaimSuccessRateWindow and ClaimSuccessRateThreshold control the rolling
	// claim-throughput warning emitted by ddx work. A full window whose claim
	// success rate is at or below the configured threshold triggers a single
	// operator-visible warning until a later successful claim clears the warned
	// state.
	ClaimSuccessRateWindow    int
	ClaimSuccessRateThreshold float64
	// BudgetStop, when non-nil, is checked before selecting the next bead. It
	// lets CLI/server callers surface already-tripped budget state as a typed
	// work-layer StopCondition before any new bead is claimed. The companion
	// report is still appended for operator visibility, but the stop itself is
	// classified through work.StopConditionBudget.
	BudgetStop func() (work.StopDecision, ExecuteBeadReport, bool)
	// BinaryRefreshCheck, when non-nil, is checked before selecting the next
	// bead. A true result means the caller has started a replacement worker
	// with equivalent arguments and this loop should exit before claiming work.
	// Errors are logged and fail open so update-probing never blocks the queue.
	BinaryRefreshCheck func(ctx context.Context) (bool, error)
	// ProjectRootDirtyCheck, when non-nil, is called at the top of each loop
	// iteration before any bead is claimed. A non-empty return value means the
	// canonical project root has uncommitted tracked non-.ddx changes. The
	// worker emits loop.operator_attention and stops instead of proceeding to
	// claim. Repeated exits for the same dirty path-set are tracked durably so
	// a relaunch can escalate into a cooldown instead of spinning immediately.
	ProjectRootDirtyCheck func(projectRoot string) []string
	// ServerHealthProbe, when non-nil, is used while the worker is in
	// server-unavailable backoff. Healthy should return true only after /api/health
	// succeeds and the lightweight smoke path is confirmed usable again.
	ServerHealthProbe func(ctx context.Context) (bool, error)
	// ServerFailureWindow bounds the distinct-bead lookback used to detect
	// repeated no_viable_provider outcomes that should be treated as a server-level
	// outage rather than a bead-level failure. Zero means use the documented
	// 10-minute default.
	ServerFailureWindow time.Duration
	// ServerFailureThreshold is the number of distinct beads that must report
	// no_viable_provider inside ServerFailureWindow before the worker enters the
	// server-unavailable probe-and-resume state. Zero means use the documented
	// default of 3.
	ServerFailureThreshold int
	// ServerHealthProbeInterval is the cadence used while the worker is in the
	// server-unavailable state. Zero means use the documented 30s default.
	ServerHealthProbeInterval time.Duration
	// Mode and IdleInterval are the runtime loop intent. Once and
	// PollInterval remain for older tests/callers but production entry points
	// should set Mode and IdleInterval directly.
	Mode         executeloop.Mode
	IdleInterval time.Duration
	Once         bool
	PollInterval time.Duration
	NoReview     bool
	// PostMergeReview enables the legacy post-land/pre-close review state
	// machine for callers that explicitly opt into that manual flow. The
	// default production close path remains owned by candidate-cycle review.
	PostMergeReview        bool
	LabelFilter            string
	IgnoreCooldown         bool
	CooldownOverrideReason string
	SessionID              string
	WorkerID               string
	ProjectRoot            string
	// TargetBeadID, when non-empty, restricts nextCandidate to only return the
	// named bead from the execution-ready queue. Used by `ddx try <bead-id>`
	// to dispatch a single specific bead through the same claim → executor →
	// land path the queue drain uses. When empty, the picker behaves normally.
	TargetBeadID string
	// WakeCh, when non-nil, signals the idle-poll sleep to return immediately
	// so the loop re-scans the queue. Used by the operator-prompt approve /
	// auto-approve mutations (Story 15) to avoid an idle-interval-sized delay
	// before a freshly-approved bead is claimed. Implementations must send
	// non-blocking (server-side helpers do); the loop only waits for a
	// receive on WakeCh during the idle sleep, never elsewhere.
	WakeCh <-chan struct{}

	// FinalizeDurableAudit, when non-nil, is called once per finalized attempt
	// after the loop has finished writing the attempt's durable tracker state.
	// Errors are terminal for autonomous work: the worker stops so DDx-managed
	// audit outputs are not left dirty while more beads are claimed.
	FinalizeDurableAudit func(report ExecuteBeadReport) error
	// PostLadderExhaustionHook, when non-nil, is called when a bead's
	// consecutive_ladder_exhaustions counter reaches the auto-recovery
	// threshold (>= 2). A nil hook or Attempted=false result falls through to
	// the existing loop path unchanged.
	PostLadderExhaustionHook PostLadderExhaustionHook
}

func (r ExecuteBeadLoopRuntime) loopIntent() (executeloop.Mode, time.Duration) {
	mode := r.Mode
	if mode == "" {
		if r.Once {
			mode = executeloop.ModeOnce
		} else {
			mode = executeloop.ModeDrain
		}
	}
	idleInterval := r.IdleInterval
	if idleInterval == 0 && mode == executeloop.ModeWatch {
		idleInterval = r.PollInterval
	}
	if idleInterval == 0 && mode == executeloop.ModeWatch {
		idleInterval = 30 * time.Second
	}
	return mode, idleInterval
}

// DefaultRouteResolutionTimeout bounds routing preflight and the resolveRoute
// viability check when ExecuteBeadLoopRuntime.RouteResolutionTimeout is unset.
// A hung resolver previously wedged the single-threaded worker for hours while
// holding a lease (ddx-8f2e0ebf); 60s is short enough to release promptly and
// long enough not to false-trip a slow-but-healthy resolver.
const DefaultRouteResolutionTimeout = 60 * time.Second

// effectiveRouteResolutionTimeout returns the configured route-resolution
// timeout, falling back to DefaultRouteResolutionTimeout when unset.
func (r ExecuteBeadLoopRuntime) effectiveRouteResolutionTimeout() time.Duration {
	if r.RouteResolutionTimeout > 0 {
		return r.RouteResolutionTimeout
	}
	return DefaultRouteResolutionTimeout
}

// DefaultConsecutiveWedgeThreshold is the number of consecutive wedges on the
// same bead that trips the consecutive-wedge guard when
// ExecuteBeadLoopRuntime.ConsecutiveWedgeThreshold is unset. A single transient
// wedge (count 1) stays below the default so the bead remains re-claimable; two
// consecutive wedges sideline it for operator attention (ddx-9714eaac).
const DefaultConsecutiveWedgeThreshold = 2

// effectiveConsecutiveWedgeThreshold returns the configured consecutive-wedge
// threshold, falling back to DefaultConsecutiveWedgeThreshold when unset.
func (r ExecuteBeadLoopRuntime) effectiveConsecutiveWedgeThreshold() int {
	if r.ConsecutiveWedgeThreshold > 0 {
		return r.ConsecutiveWedgeThreshold
	}
	return DefaultConsecutiveWedgeThreshold
}

// DefaultClaimSuccessRateWindow is the number of recent claim attempts used to
// compute the rolling claim-success rate warning.
const DefaultClaimSuccessRateWindow = 10

// effectiveClaimSuccessRateWindow returns the configured claim-success window,
// falling back to DefaultClaimSuccessRateWindow when unset.
func (r ExecuteBeadLoopRuntime) effectiveClaimSuccessRateWindow() int {
	if r.ClaimSuccessRateWindow > 0 {
		return r.ClaimSuccessRateWindow
	}
	return DefaultClaimSuccessRateWindow
}

// DefaultClaimSuccessRateThreshold is the minimum rolling claim-success rate
// before the loop emits a warning. Zero means only a full window of
// non-successes trips the signal.
const DefaultClaimSuccessRateThreshold = 0.0

// effectiveClaimSuccessRateThreshold returns the configured claim-success
// threshold, falling back to DefaultClaimSuccessRateThreshold when unset.
func (r ExecuteBeadLoopRuntime) effectiveClaimSuccessRateThreshold() float64 {
	if r.ClaimSuccessRateThreshold >= 0 {
		return r.ClaimSuccessRateThreshold
	}
	return DefaultClaimSuccessRateThreshold
}

