package agent

// provider_failure.go defines the typed provider-failure taxonomy at the
// DDx/Fizeau boundary (ddx-3b721804). A provider failure is any pre-dispatch
// Execute error or failed final event whose root cause is provider/model
// availability, credentials, quota/rate limiting, endpoint reachability, or
// harness/configuration validity — as opposed to a model giving up on the task.
//
// DDx is the abstraction that lets unattended workers continue through provider
// variance across machines. A generic, untyped provider failure that names no
// cause, no fallback action, and no route-health evidence is a product bug, so
// this file gives every such failure a typed reason, a retryability verdict, a
// fallback decision, and durable evidence.
//
// Routing itself stays in Fizeau (aliases, model discovery, provider catalog);
// DDx only classifies the outcome and decides whether an unpinned worker should
// fall back to another eligible route or a pinned worker should fail loudly.

import (
	"errors"
	"strings"

	agentlib "github.com/easel/fizeau"
)

// Provider-failure taxonomy. provider_connectivity and no_viable_provider reuse
// the existing FailureMode* constants (execute_bead_status.go) so the rest of
// the loop's route-health handling continues to recognize them.
const (
	FailureModeProviderAuth               = "provider_auth"
	FailureModeProviderRateLimit          = "provider_rate_limit"
	FailureModeProviderQuota              = "provider_quota"
	FailureModeProviderModelUnavailable   = "provider_model_unavailable"
	FailureModeProviderHarnessUnavailable = "provider_harness_unavailable"
	FailureModeProviderConfigInvalid      = "provider_config_invalid"
	FailureModeUnknownProviderFailure     = "unknown_provider_failure"
)

// ProviderFailure is the typed classification of a provider/route failure.
type ProviderFailure struct {
	// Reason is one of the taxonomy constants above (or the reused
	// FailureModeProviderConnectivity / FailureModeNoViableProvider).
	Reason string
	// Retryable reports whether a *different* eligible route could succeed.
	// True for transient/availability failures an unpinned worker should fall
	// back from; false for whole-fleet conditions (no viable provider) or
	// configuration bugs that another route cannot fix.
	Retryable bool
	// Disruption is the disruption_reason stamped on the report. A provider
	// failure is always a worker-side disruption (the model never got to give
	// up), so it mirrors Reason.
	Disruption string
}

// ProviderFailureError wraps a pre-dispatch Execute error with its typed
// classification so callers can recover the taxonomy via errors.As without
// re-parsing free text. The wrapped error's message is preserved verbatim.
type ProviderFailureError struct {
	Failure ProviderFailure
	Err     error
}

func (e *ProviderFailureError) Error() string {
	if e == nil || e.Err == nil {
		return ""
	}
	return e.Err.Error()
}

func (e *ProviderFailureError) Unwrap() error {
	if e == nil {
		return nil
	}
	return e.Err
}

// ClassifyProviderFailure normalizes a free-text provider/route error into the
// typed taxonomy. It returns ok=false when the text does not name a recognized
// provider/route/config cause, so callers can leave non-provider failures
// (test_failure, merge_conflict, ...) classified by ClassifyFailureMode.
//
// The order is significant: config-invalid and auth/quota/rate-limit markers
// are checked before the broad connectivity bucket so a "429" or "unauthorized"
// is not swallowed as a generic timeout.
func ClassifyProviderFailure(errMsg string) (ProviderFailure, bool) {
	lower := strings.ToLower(strings.TrimSpace(errMsg))
	if lower == "" {
		return ProviderFailure{}, false
	}
	switch {
	case containsAny(lower,
		"passthrough constraint unsatisfiable",
		"passthrough constraint:",
		"invalid configuration",
		"config invalid",
		"invalid endpoint",
		"misconfigured",
		"unknown provider",
		"harness model incompatible",
		"model incompatible with",
		"incompatible with power bounds"):
		return providerFailure(FailureModeProviderConfigInvalid, false), true
	case containsAny(lower,
		"unauthorized",
		"401",
		"invalid api key",
		"invalid_api_key",
		"authentication failed",
		"authentication_error",
		"no api key",
		"missing api key",
		"forbidden",
		"403"):
		return providerFailure(FailureModeProviderAuth, true), true
	case containsAny(lower,
		"quota exceeded",
		"insufficient quota",
		"insufficient_quota",
		"out of quota",
		"quota"):
		return providerFailure(FailureModeProviderQuota, true), true
	case containsAny(lower,
		"rate limit",
		"rate_limit",
		"ratelimit",
		"too many requests",
		"429"):
		return providerFailure(FailureModeProviderRateLimit, true), true
	case containsAny(lower, "is not routable", "not routable", "model_not_found"),
		strings.Contains(lower, "model") && containsAny(lower,
			"not available",
			"unavailable",
			"not found",
			"no such",
			"unknown",
			"incompatible"):
		return providerFailure(FailureModeProviderModelUnavailable, true), true
	case containsAny(lower,
		"harness unavailable",
		"harness not available",
		"harness not installed",
		"unknown harness",
		"no harness configured",
		"executable file not found",
		"command not found"):
		return providerFailure(FailureModeProviderHarnessUnavailable, true), true
	case containsAny(lower,
		"no viable provider",
		"no viable harness",
		"no viable routing candidate",
		"no live provider supports",
		"no candidate satisfying local endpoint"):
		return providerFailure(FailureModeNoViableProvider, false), true
	case containsAny(lower,
		"connection refused",
		"connection reset",
		"no route to host",
		"network is unreachable",
		"no such host",
		"i/o timeout",
		"dial tcp",
		"provider_connectivity",
		"provider request timeout",
		"provider timeout",
		"endpoint timeout",
		"bad gateway",
		"service unavailable",
		"gateway timeout",
		"502", "503", "504"):
		return providerFailure(FailureModeProviderConnectivity, true), true
	}
	return ProviderFailure{}, false
}

// ClassifyServiceExecuteError classifies a pre-dispatch FizeauService.Execute
// error. Because a pre-dispatch failure means routing never produced a viable
// dispatch, every such error is a provider-boundary failure: when no specific
// marker matches it falls back to unknown_provider_failure (non-retryable) so
// the outcome is always typed rather than generic execution_failed.
func ClassifyServiceExecuteError(err error) ProviderFailure {
	if err == nil {
		return providerFailure(FailureModeUnknownProviderFailure, false)
	}
	var modelErr *agentlib.ErrHarnessModelIncompatible
	if errors.As(err, &modelErr) {
		return providerFailure(FailureModeProviderModelUnavailable, true)
	}
	if pf, ok := ClassifyProviderFailure(err.Error()); ok {
		return pf
	}
	return providerFailure(FailureModeUnknownProviderFailure, false)
}

// ApplyProviderFailureToReport stamps a typed provider failure onto a report:
// the typed reason as outcome_reason and the worker-disruption markers so the
// retry/fallback layer treats it as route-health evidence, not a model give-up.
func ApplyProviderFailureToReport(report *ExecuteBeadReport, pf ProviderFailure) {
	if report == nil || pf.Reason == "" {
		return
	}
	report.OutcomeReason = pf.Reason
	report.Disrupted = true
	report.DisruptionReason = pf.Disruption
}

// IsProviderFailureReason reports whether reason is one of the typed
// provider-failure taxonomy values (including the reused connectivity /
// no-viable-provider reasons).
func IsProviderFailureReason(reason string) bool {
	switch strings.TrimSpace(reason) {
	case FailureModeProviderAuth,
		FailureModeProviderRateLimit,
		FailureModeProviderQuota,
		FailureModeProviderModelUnavailable,
		FailureModeProviderHarnessUnavailable,
		FailureModeProviderConfigInvalid,
		FailureModeUnknownProviderFailure,
		FailureModeProviderConnectivity,
		FailureModeNoViableProvider:
		return true

				wallClockTimedOut.Store(true)
				wallClockElapsed.Store(int64(time.Since(wallClockStart)))
				cancel()
				stopProcess()
			}
		}()
	}

	// Stream stdout to collect it and count any write as progress.
	stdoutDone := make(chan struct{})
	go func() {
		defer close(stdoutDone)
		_, _ = io.Copy(&activityWriter{Buffer: &stdoutBuf, OnWrite: pulse}, stdoutPipe)
	}()

	// Stream stderr: collect it, count progress, and watch for cancel patterns.
	stderrDone := make(chan struct{})
	go func() {
		defer close(stderrDone)
		scanner := bufio.NewScanner(stderrPipe)
		for scanner.Scan() {
			line := scanner.Text()
			stderrBuf.WriteString(line)
			stderrBuf.WriteByte('\n')
			pulse()
			if cancelReason == "" {
				if reason := matchesCancelPattern(line); reason != "" {
					cancelReason = reason
					cancel()
					stopProcess()
				}
			}
		}
		// Drain any remaining bytes not caught by the scanner.
		_, _ = io.Copy(&activityWriter{Buffer: &stderrBuf, OnWrite: pulse}, stderrPipe)
	}()

	<-stdoutDone
	<-stderrDone
	runErr := cmd.Wait()

	result := &ExecResult{
		Stdout:           stdoutBuf.String(),
		Stderr:           stderrBuf.String(),
		EarlyCancel:      cancelReason != "",
		CancelReason:     cancelReason,
		WallClockTimeout: wallClockTimedOut.Load(),
		WallClockElapsed: time.Duration(wallClockElapsed.Load()),
	}

	if runErr != nil {
		if cancelReason != "" {
			// We triggered the cancel; report as early-cancel rather than timeout.
			result.ExitCode = -1
			return result, nil
		}
		if wallClockTimedOut.Load() {
			result.ExitCode = -1
			return result, context.DeadlineExceeded
		}
		if timedOut.Load() {
			result.ExitCode = -1
			return result, context.DeadlineExceeded
		}
		if errors.Is(ctx.Err(), context.Canceled) || errors.Is(ctx.Err(), context.DeadlineExceeded) {
			result.ExitCode = -1
			return result, ctx.Err()
		}
		if exitErr, ok := runErr.(*exec.ExitError); ok {
			result.ExitCode = exitErr.ExitCode()
			return result, nil // non-zero exit is not an execution error
		}
		return result, runErr
	}
	return result, nil
}

func envWithOverrides(base []string, overrides map[string]string) []string {
	if len(base) == 0 && len(overrides) == 0 {
		return nil
	}
	if len(overrides) == 0 {
		return append([]string{}, base...)
	}

	skip := make(map[string]bool, len(overrides))
	keys := make([]string, 0, len(overrides))
	for key := range overrides {
		skip[key] = true
		keys = append(keys, key)
	}
	sort.Strings(keys)

	env := make([]string, 0, len(base)+len(overrides))
	for _, kv := range base {
		eq := strings.IndexByte(kv, '=')
		if eq < 0 {
			env = append(env, kv)
			continue
		}
		if skip[kv[:eq]] {
			continue
		}
		env = append(env, kv)
	}
	for _, key := range keys {
		env = append(env, key+"="+overrides[key])
	}
	return env
}

type activityWriter struct {
	Buffer  *bytes.Buffer
	OnWrite func()
}

func (w *activityWriter) Write(p []byte) (int, error) {
	if len(p) > 0 && w.OnWrite != nil {
		w.OnWrite()
	}
	return w.Buffer.Write(p)

	anyFailed := false
	anyRatchetFailed := false
	results := make([]GateCheckResult, 0, len(candidates))
	for _, c := range candidates {
		cwd := wtPath
		if c.cwd != "" {
			if filepath.IsAbs(c.cwd) {
				cwd = c.cwd
			} else {
				cwd = filepath.Join(wtPath, c.cwd)
			}
		}

		ctx, cancel := context.WithTimeout(context.Background(), 5*time.Minute)
		cmd := osexec.CommandContext(ctx, c.command[0], c.command[1:]...)
		cmd.Dir = cwd
		var stdoutBuf, stderrBuf strings.Builder
		cmd.Stdout = &stdoutBuf
		cmd.Stderr = &stderrBuf
		runErr := cmd.Run()
		cancel()

		stdoutStr := strings.TrimSpace(stdoutBuf.String())
		stderrStr := strings.TrimSpace(stderrBuf.String())
		gr := GateCheckResult{
			DefinitionID: c.id,
			Required:     true,
			Stdout:       stdoutStr,
			Stderr:       stderrStr,
		}
		if runErr != nil {
			gr.ExitCode = 1
			if exitErr, ok := runErr.(*osexec.ExitError); ok {
				gr.ExitCode = exitErr.ExitCode()
			}
			gr.Status = "fail"
			anyFailed = true
		} else {
			gr.Status = "pass"
		}

		// Apply ratchet evaluation when thresholds are declared. Only runs
		// when the command exited cleanly — a non-zero exit already failed
		// the gate and there's no point parsing unreliable output.
		if c.thresholds != nil && gr.Status == "pass" {
			evidence := evaluateRatchet(c.id, c.comparison, c.thresholds, c.metric, stdoutStr, stderrStr)
			gr.Ratchet = evidence
			if evidence.Decision == "fail" {
				gr.Status = "fail"
				anyFailed = true
				anyRatchetFailed = true
			}
		}
		results = append(results, gr)
	}

	return results, anyFailed, anyRatchetFailed, nil
}

// evaluateRatchet parses the gate's observed value from stdout and compares it
// against the declared ratchet threshold. Always returns a non-nil evidence
// record so pass/fail results both carry machine-readable provenance.
func evaluateRatchet(definitionID, comparison string, thresholds *docgraph.DocThresholds, metric *docgraph.DocMetricSpec, stdout, stderr string) *RatchetEvidence {
	if comparison == "" {
		comparison = "lower-is-better"
	}
	unit := ""
	metricID := ""
	if metric != nil {
		unit = metric.Unit
		metricID = metric.MetricID
	}
	if unit == "" {
		unit = thresholds.Unit
	}
	observed, parsedUnit, parsed := parseGateValue(stdout)
	if !parsed {
		// Fall back to stderr for tools that report numbers there.
		observed, parsedUnit, parsed = parseGateValue(stderr)
	}
	if unit == "" {
		unit = parsedUnit
	}
	evidence := &RatchetEvidence{
		DefinitionID: definitionID,
		MetricID:     metricID,
		Comparison:   comparison,
		Threshold:    thresholds.Ratchet,
		Observed:     observed,
		Unit:         unit,
	}
	if !parsed {
		evidence.Decision = "fail"
		evidence.Reason = "gate did not emit a parseable numeric value"
		return evidence
	}
	passed := ratchetPasses(comparison, thresholds.Ratchet, observed)
	if passed {
		evidence.Decision = "pass"
		evidence.Reason = formatRatchetReason(comparison, thresholds.Ratchet, observed, unit, true)
	} else {

		"resolveroute:",
		"no viable routing candidate",
		"no live provider supports",
		"no candidate satisfying local endpoint")
}

// classifyDisruption examines the loop ctx and the executor's error to decide
// whether a failed ExecuteBead attempt was caused by external disruption
// (worker killed, context cancelled, transport error) rather than the model
// genuinely producing nothing. Returns ok=true plus a short reason kind when
// disruption is detected; the caller marks the report Disrupted to bypass the
// no-progress cooldown (ddx-5b3e57f4). Reason kinds are stable strings used
// in the disruption_detected event:
//
//	context_canceled, context_deadline, transport_error
func classifyDisruption(ctx context.Context, executorErr error) (string, bool) {
	if ctx != nil {
		switch ctx.Err() {
		case context.Canceled:
			return "context_canceled", true
		case context.DeadlineExceeded:
			return "context_deadline", true
		}
	}
	if executorErr == nil {
		return "", false
	}
	if isTransportError(executorErr) {
		return "transport_error", true
	}
	return "", false
}

func loopContextErr(ctx context.Context) error {
	if ctx == nil {
		return nil
	}
	switch err := ctx.Err(); err {
	case context.Canceled, context.DeadlineExceeded:
		return err
	default:
		return nil
	}
}

// isTransportError returns true when err looks like a transport-class failure
// (network reset, connection refused, TLS error, gateway, provider 5xx). The
// signal is fuzzy on purpose: callers (classifyDisruption) only use it to
// flag a failure as Disrupted so the bead skips the long no-progress cooldown
// and is retried promptly. False positives are cheap (one quick retry); false
// negatives are expensive (6h park for a transient outage).
func isTransportError(err error) bool {
	if err == nil {
		return false
	}
	msg := strings.ToLower(err.Error())
	for _, marker := range []string{
		"connection refused",
		"connection reset",
		"connection closed",
		"no route to host",
		"network is unreachable",
		"i/o timeout",
		"context deadline exceeded",
		"tls handshake",
		"eof",
		"broken pipe",
		"bad gateway",
		"service unavailable",
		"gateway timeout",
		"transport",
	} {
		if strings.Contains(msg, marker) {
			return true
		}
	}
	return false
}

// emitDisruptionDetected records a structured `disruption_detected` event for
// the bead and the loop event sink so operators can see disruption rates and
// which class is firing (ddx-5b3e57f4 AC #5).
