func recordServiceRouteAttempt(ctx context.Context, svc agentlib.FizeauService, result *Result, elapsed time.Duration, finishedAt time.Time) {
	if svc == nil || result == nil || strings.TrimSpace(result.Provider) == "" {
		return
	}
	status := "success"
	reason := "success"
	if result.ExitCode != 0 || strings.TrimSpace(result.Error) != "" {
		status = "failed"
		reason = "execution_failed"
		if strings.TrimSpace(result.Error) != "" {
			reason = "provider_error"
		}
	}
	_ = svc.RecordRouteAttempt(ctx, agentlib.RouteAttempt{
		Harness:   result.Harness,
		Provider:  result.Provider,
		Model:     result.Model,
		Status:    status,
		Reason:    reason,
		Error:     result.Error,
		Duration:  elapsed,
		Timestamp: finishedAt,
	})
}

func metadataWithEnv(metadata, env map[string]string) map[string]string {
	if len(metadata) == 0 && len(env) == 0 {
		return nil
	}
	out := make(map[string]string, len(metadata)+len(env))
	for k, v := range metadata {
		out[k] = v
	}
	for k, v := range env {
		out[k] = v
	}
	return out
}

func normalizeServiceFinalExitCode(result *Result) {
	if result == nil {
		return
	}
	if result.ExitCode == 0 && strings.TrimSpace(result.Error) != "" {
		result.ExitCode = 1
	}
}

// CapabilitiesViaService returns HarnessCapabilities for the named harness by
// querying the service's ListHarnesses and (best-effort) the harness registry.
// It is the production replacement for Runner.Capabilities.
func CapabilitiesViaService(ctx context.Context, workDir, harnessName string) (*HarnessCapabilities, error) {
	if ctx == nil {
		ctx = context.Background()
	}
	svc, err := ResolvePreflightServiceFromWorkDir(workDir)
	if err != nil {
		return nil, fmt.Errorf("agent: build service: %w", err)
	}
	infos, err := svc.ListHarnesses(ctx)
	if err != nil {
		return nil, fmt.Errorf("agent: list harnesses: %w", err)
	}
	var info *agentlib.HarnessInfo
	for i := range infos {
		if infos[i].Name == harnessName {
			info = &infos[i]
			break
		}
	}
	if info == nil {
		return nil, fmt.Errorf("agent: unknown harness: %s", harnessName)
	}

	// Pull binary and reasoning-level metadata from the local registry — the
	// service does not expose these directly today.
	registry := newHarnessRegistry()
	harness, _ := registry.Get(harnessName)

	caps := &HarnessCapabilities{
		Harness:             info.Name,
		Available:           info.Available,
		Binary:              harness.Binary,
		Path:                info.Path,
		Surface:             harness.Surface,
		CostClass:           info.CostClass,
		IsLocal:             info.CostClass == "local",
		ExactPinSupport:     info.ExactPinSupport,
		SupportsEffort:      len(info.SupportedReasoning) > 0 || harness.EffortFlag != "",
		SupportsPermissions: len(info.SupportedPermissions) > 0 || len(harness.PermissionArgs) > 0,
	}
	if len(info.SupportedReasoning) > 0 {
		caps.ReasoningLevels = append([]string{}, info.SupportedReasoning...)
	} else if len(harness.ReasoningLevels) > 0 {

	// Append permission-specific args.
	if h.PermissionArgs != nil {
		level := in.Permissions
		if level == "" {
			level = "safe"
		}
		if extra, ok := h.PermissionArgs[level]; ok {
			args = append(args, extra...)
		}
	}

	if in.WorkDir != "" && h.WorkDirFlag != "" {
		args = append(args, h.WorkDirFlag, in.WorkDir)
	}
	if model != "" && h.ModelFlag != "" {
		args = append(args, h.ModelFlag, model)
	}
	if in.Effort != "" && h.EffortFlag != "" {
		if h.EffortFormat != "" {
			args = append(args, h.EffortFlag, fmt.Sprintf(h.EffortFormat, in.Effort))
		} else {
			args = append(args, h.EffortFlag, in.Effort)
		}
	}
	if h.PromptMode == "arg" {
		args = append(args, in.Prompt)
	}
	return args
}

// processResult converts execution output to a Result.
func (r *Runner) processResult(harnessName, model string, harness harnessConfig, execResult *ExecResult, execErr error, elapsed time.Duration, ctx context.Context) *Result {
	result := &Result{
		Harness:    harnessName,
		Model:      model,
		DurationMS: int(elapsed.Milliseconds()),
	}

	if execResult != nil {
		result.Output = execResult.Stdout
		result.Stderr = execResult.Stderr
		result.ExitCode = execResult.ExitCode
	}

	if execResult != nil && execResult.EarlyCancel {
		result.Error = fmt.Sprintf("cancelled: auth/rate-limit detected (%s)", execResult.CancelReason)
		result.ExitCode = -1
	} else if execResult != nil && execResult.WallClockTimeout {
		// Wall-clock cap fired regardless of stream activity; distinguish
		// this from the resettable idle timer so operators can tell the two
		// failure modes apart in result.json and session logs.
		reportedElapsed := execResult.WallClockElapsed
		if reportedElapsed == 0 {
			reportedElapsed = elapsed
		}
		result.Error = fmt.Sprintf("wall-clock deadline exceeded after %v", reportedElapsed.Round(time.Second))
		result.ExitCode = -1
	} else if execErr != nil {
		if errors.Is(execErr, context.DeadlineExceeded) || errors.Is(ctx.Err(), context.DeadlineExceeded) {
			result.Error = fmt.Sprintf("timeout after %v", elapsed.Round(time.Second))
			result.ExitCode = -1
		} else {
			result.Error = execErr.Error()
			if result.ExitCode == 0 {
				result.ExitCode = -1
			}
		}
	} else if execResult != nil && execResult.ExitCode != 0 {
		result.Error = execResult.Stderr
	}

	result.Tokens = ExtractTokens(result.Output, harness)
	usage := ExtractUsage(harnessName, result.Output)
	result.InputTokens = usage.InputTokens
	result.CachedTokens = usage.CachedTokens
	result.OutputTokens = usage.OutputTokens
	result.CostUSD = usage.CostUSD
	return result
}

// UsageData holds structured token usage from a structured agent output.
type UsageData struct {
	InputTokens  int
	CachedTokens int
	OutputTokens int
	CostUSD      float64
}

// ExtractUsage parses structured token usage from agent output.
// For codex, it scans JSONL output for a turn.completed event and reads the usage object.
// For claude, it parses the --output-format json envelope (whole output or last non-empty line).
// Returns zero-value UsageData if parsing fails or the harness is unsupported.
func ExtractUsage(harnessName string, output string) UsageData {
	switch harnessName {
	case "codex":
		for _, line := range strings.Split(output, "\n") {
			line = strings.TrimSpace(line)
			if line == "" || !strings.Contains(line, `"turn.completed"`) {
				continue
			}

