	executorPdeathsigChildPIDFileEnv = "DDX_EXECUTOR_PDEATHSIG_CHILD_PID_FILE"
	executorPdeathsigGrandPIDFileEnv = "DDX_EXECUTOR_PDEATHSIG_GRANDCHILD_PID_FILE"
