type sourceCheckoutBinaryStaleness struct {
	ProjectRoot  string
	BinaryCommit string
	SourceHead   string
	AheadCount   string
}

var ddxBinaryStalenessPathspecs = []string{
	"Makefile",
	"install.sh",
	"cli",
}

func (s sourceCheckoutBinaryStaleness) recoveryCommand() string {
	return fmt.Sprintf("cd %s && make install", s.ProjectRoot)
}

func (s sourceCheckoutBinaryStaleness) warningMessage() string {
	return fmt.Sprintf(
		"WARNING: installed ddx is built from %s; source tree HEAD is %s (%s commits ahead).\nproject root: %s\nbinary commit: %s\nsource HEAD: %s\ninstalled ddx binary is behind this DDx source checkout.\nrecovery: %s\nRun \"make install\" to refresh.\n",
		s.BinaryCommit,
		s.SourceHead,
		s.AheadCount,
		s.ProjectRoot,
		s.BinaryCommit,
		s.SourceHead,
		s.recoveryCommand(),
	)
}

func (f *CommandFactory) detectInstalledBinaryBehindSource(projectRoot string) *sourceCheckoutBinaryStaleness {
	if f.Version == "" || f.Version == "dev" {
		return nil
	}

	buildCommit := normalizeVersionCommit(f.Commit)
	if buildCommit == "" {
		return nil
	}

	repoRoot := strings.TrimSpace(projectRoot)
	if repoRoot == "" {
		return nil
	}
	if !gitpkg.IsRepository(repoRoot) {
		repoRoot = gitpkg.FindProjectRoot(repoRoot)
	}
	if repoRoot == "" || !gitpkg.IsRepository(repoRoot) {
		return nil
	}

	originURL, err := gitCommandOutput(repoRoot, "remote", "get-url", "origin")
	if err != nil || !isDDXOriginURL(originURL) {
		return nil
	}

	buildSHA, err := gitResolveCommit(repoRoot, buildCommit)
	if err != nil {
		return nil
	}
	headSHA, err := gitCommandOutput(repoRoot, "rev-parse", "HEAD")
	if err != nil || buildSHA == headSHA {
		return nil
	}

	if err := gitpkg.Command(context.Background(), repoRoot, "merge-base", "--is-ancestor", buildSHA, headSHA).Run(); err != nil {
		return nil
	}

	aheadCount, err := gitCommandOutput(repoRoot, "rev-list", "--count", buildSHA+".."+headSHA)
	if err != nil || aheadCount == "0" {
		return nil
	}
	if !hasDDXBinaryAffectingDiff(repoRoot, buildSHA, headSHA) {
		return nil
	}

	return &sourceCheckoutBinaryStaleness{
		ProjectRoot:  repoRoot,
		BinaryCommit: buildSHA,
		SourceHead:   headSHA,
		AheadCount:   aheadCount,
	}
}

func (f *CommandFactory) warnIfInstalledBinaryBehindSource(cmd *cobra.Command) {
	repoRoot := gitpkg.FindProjectRoot(f.WorkingDir)
	staleness := f.detectInstalledBinaryBehindSource(repoRoot)
	if staleness == nil {
		return
	}
	_, _ = fmt.Fprint(cmd.ErrOrStderr(), staleness.warningMessage())
}

func hasDDXBinaryAffectingDiff(repoRoot, baseSHA, headSHA string) bool {
	args := []string{"diff", "--name-only", baseSHA + ".." + headSHA, "--"}
	args = append(args, ddxBinaryStalenessPathspecs...)
	out, err := gitCommandOutput(repoRoot, args...)
	return err == nil && strings.TrimSpace(out) != ""
}

func gitCommandOutput(dir string, args ...string) (string, error) {
	out, err := gitpkg.Command(context.Background(), dir, args...).Output()
	if err != nil {
		return "", err
	}
	return strings.TrimSpace(string(out)), nil
}

func gitResolveCommit(dir, commit string) (string, error) {
	return gitCommandOutput(dir, "rev-parse", "--verify", commit+"^{commit}")
}

func isDDXOriginURL(url string) bool {
	return strings.Contains(strings.ToLower(url), "documentdrivendx/ddx")
}

// resolveAgentSession looks up a session by ID from the agent session log.
// Returns nil if the session is not found or cannot be read.
func (f *CommandFactory) resolveAgentSession(sessionID string) *agent.SessionEntry {
	if sessionID == "" {
		return nil
	}

	cfg, err := config.LoadWithWorkingDir(f.WorkingDir)
	if err != nil {
		return nil
	}

	sessionLogDir := ".ddx/agent-logs"
	if cfg.Agent != nil && cfg.Agent.SessionLogDir != "" {
		sessionLogDir = cfg.Agent.SessionLogDir
	}

	logDir := agent.ResolveLogDir(f.WorkingDir, sessionLogDir)
	idx, ok, err := agent.FindSessionIndex(logDir, sessionID)
	if err != nil {
		return nil
	}
	if ok {
		entry := agent.SessionIndexEntryToLegacy(idx)
		bodies := agent.LoadSessionBodies(f.WorkingDir, idx)
		entry.Prompt = bodies.Prompt
		entry.Response = bodies.Response

func (f *CommandFactory) runAgentExecuteLoopImpl(cmd *cobra.Command, treatPassthroughAsOpaque bool, tryTargetBeadID string) error {
	spec, dispatch, err := parseExecuteLoopSpec(cmd, treatPassthroughAsOpaque)
	if err != nil {
		return err
	}
	projectFlag := spec.ProjectRoot
	projectRoot := resolveProjectRoot(projectFlag, f.WorkingDir)
	spec.ProjectRoot = projectRoot
	beadStoreRoot := f.commandBeadStoreRoot(projectFlag, projectRoot)
	if tryTargetBeadID != "" {
		spec.Mode = executeloop.ModeOnce
		spec.IdleInterval = executeloop.Duration{}
	}
	spec.Profile = agent.NormalizeRoutingProfile(spec.Profile)

	noRoutingFlags := spec.Harness == "" && spec.Model == "" && spec.Provider == "" &&
		spec.Profile == "" && spec.MinPower == 0 &&
		spec.MaxPower == 0 && !cmd.Flags().Changed("harness") &&
		!cmd.Flags().Changed("model") && !cmd.Flags().Changed("provider") &&
		!cmd.Flags().Changed("profile") &&
		!cmd.Flags().Changed("min-power") && !cmd.Flags().Changed("max-power")
	hasProjectRoutingConfig := projectHasRoutingConfig(projectRoot)
	autoInferPowerClass := noRoutingFlags && !hasProjectRoutingConfig

	store := bead.NewStore(beadStoreRoot)
	workerStore := agent.ExecuteBeadLoopStore(store)
	if spec.IgnoreCooldown {
		workerStore = newIgnoreCooldownStore(store)
	}
	jsonOutput := dispatch.JSON == "true"
	cleanupLog := cmd.ErrOrStderr()
	if jsonOutput {
		cleanupLog = io.Discard
	}
	cleanupRunner := newStartupHousekeepingRunner(projectRoot)
	if tryTargetBeadID == "" && spec.Mode != executeloop.ModeWatch {
		if breakdown, bErr := store.ReadyExecutionBreakdown(); bErr != nil {
			return bErr
		} else if len(breakdown.ExecutionReady) == 0 && len(breakdown.RetryCooldown) == 0 {
			if _, cleanupErr := cleanupRunner.Cleanup(cmd.Context()); cleanupErr != nil {
				return cleanupErr
			}
			return writeExecuteLoopResult(cmd.OutOrStdout(), projectRoot, agent.NewNoReadyWorkLoopResult(spec.Mode, breakdown), jsonOutput)
		}
	}

	loopSessionID := fmt.Sprintf("agent-loop-%d", time.Now().UnixNano())
	loopLogDir := filepath.Join(projectRoot, agent.DefaultLogDir)
	_ = os.MkdirAll(loopLogDir, 0o755)
	loopLogPath := filepath.Join(loopLogDir, loopSessionID+".jsonl")
	var loopSink io.Writer
	if lf, err := os.OpenFile(loopLogPath, os.O_CREATE|os.O_WRONLY|os.O_APPEND, 0o644); err == nil {
		loopSink = lf
		defer lf.Close() //nolint:errcheck
	}

	probeIdent := workerprobe.Identity{
		ProjectRoot:  projectRoot,
		Harness:      spec.Harness,
		Model:        spec.Model,
		ExecutorPID:  os.Getpid(),
		ExecutorHost: hostnameOrEmpty(),
		StartedAt:    time.Now().UTC(),
	}
	probe := workerprobe.New(probeIdent, workerprobe.Config{AddrFunc: serverpkg.ReadServerAddr})
	probeCtx, probeCancel := context.WithCancel(context.Background())
	probe.Start(probeCtx)
	defer func() {
		probeCancel()
		probe.Stop()
	}()
	if loopSink != nil {
		loopSink = workerprobe.TeeJSONL(loopSink, probe)
	} else {
		loopSink = workerprobe.TeeJSONL(io.Discard, probe)
	}

	localCoord := serverpkg.NewLocalLandCoordinator(projectRoot, agent.RealLandingGitOps{})
	defer localCoord.Stop()

	var reviewer agent.BeadReviewer
	if !spec.NoReview {
		reviewer = &agent.DefaultBeadReviewer{
			ProjectRoot: projectRoot,
			BeadStore:   bead.NewStore(beadStoreRoot),
			BeadEvents:  bead.NewStore(beadStoreRoot),
			Harness:     spec.ReviewHarness,
			Model:       spec.ReviewModel,
		}
	}

	overrides := config.CLIOverrides{
		Assignee:          resolveClaimAssignee(),
		Harness:           spec.Harness,
		Model:             spec.Model,
		Provider:          spec.Provider,
		Profile:           spec.Profile,
		Effort:            spec.Effort,
		MinPower:          spec.MinPower,
		MaxPower:          spec.MaxPower,
		OpaquePassthrough: spec.OpaquePassthrough,
	}
	rcfg, err := config.LoadAndResolve(projectRoot, overrides)
	if err != nil {
		return fmt.Errorf("load resolved config: %w", err)
	}
	serverHealthProbe := func(ctx context.Context) (bool, error) {
		addr := serverpkg.ReadServerAddr()
		if strings.TrimSpace(addr) == "" {
			return false, nil
		}
		req, err := http.NewRequestWithContext(ctx, http.MethodGet, strings.TrimRight(addr, "/")+"/api/health", nil)
		if err != nil {
			return false, err
		}
		client := &http.Client{Timeout: 5 * time.Second}
		resp, err := client.Do(req)
		if err != nil {
			return false, err
		}
		defer func() { _ = resp.Body.Close() }()
		if resp.StatusCode != http.StatusOK {
			return false, fmt.Errorf("server health status %s", resp.Status)
		}
		smokeCtx, cancel := context.WithTimeout(ctx, 15*time.Second)
		defer cancel()
		smokeResult, smokeErr := agent.RunWithConfigViaService(smokeCtx, projectRoot, rcfg, agent.AgentRunRuntime{
			Prompt:  "server health smoke test",
			WorkDir: projectRoot,
		})
		if smokeErr != nil {
			return false, smokeErr
		}
		return smokeResult != nil && smokeResult.ExitCode == 0, nil
	}

	resourceChecker := buildCLIResourceChecker(projectRoot, f.resourceCheckerOverride)
	if _, err := resourceChecker.Check(cmd.Context()); err != nil {
		var resourceErr *agent.ResourceExhaustedError
		if errors.As(err, &resourceErr) {
			_, _ = fmt.Fprintln(cmd.OutOrStdout(), agent.ResourceExhaustedStopMessage)
		}
		return err
	}

	var qualityRunner agent.AgentRunner
	if f.AgentRunnerOverride != nil {
		qualityRunner = f.AgentRunnerOverride
	}
	lintHook := agent.NewPreDispatchLintHook(projectRoot, store, rcfg, nil, qualityRunner)
	intakeLog := cmd.OutOrStdout()
	if dispatch.JSON == "true" {
		intakeLog = io.Discard
	}
	innerIntakeHook := agent.NewPreClaimIntakeHookWithLogVerbose(projectRoot, store, rcfg, nil, qualityRunner, intakeLog, f.viperInstance.GetBool("verbose"))
	intakeHook := agent.NewACQualityPreClaimGate(store, rcfg.BeadQualityMode(), rcfg.ACQualityMinScore(), innerIntakeHook)
	triageHook := agent.NewPostAttemptTriageHook(projectRoot, store, rcfg, nil, qualityRunner, nil)
	proseHook := f.proseEvidenceHookOverride
	if proseHook == nil {
		proseHook = agent.NewDefaultProseEvidenceHook(agent.ProseEvidenceConfig{
			ProjectRoot: projectRoot,
			Events:      bead.NewStore(beadStoreRoot),
			Actor:       resolveClaimAssignee(),
			Source:      "ddx work",
		})
	}
	decompositionHook := agent.NewPreClaimDecompositionHook(store, qualityRunner, rcfg, projectRoot)
	recoveryHook := agent.NewAutoRecoveryPostLadderExhaustionHook(store, qualityRunner, rcfg, projectRoot, agent.AutoRecoveryConfig{
		MaxRecoveryCostUSD: spec.MaxRecoveryCostUSD,
		MaxBeadCostUSD:     spec.MaxBeadCostUSD,
	})

	harnessBilledLookup := func(harnessName string) bool {
		svc, svcErr := agent.ResolvePreflightServiceFromWorkDir(f.WorkingDir)
		if svcErr != nil {
			return true
		}
		infos, err := svc.ListHarnesses(context.Background())
		if err != nil {
			return true
		}
		for _, h := range infos {
			if h.Name == harnessName {
				return escalation.CountsTowardCostCap(h.CostClass == "local", h.Billing == agentlib.BillingModelSubscription, h.CostClass)
			}
		}
		return true
	}

	costCap := escalation.NewCostCapTracker(spec.MaxCostUSD, harnessBilledLookup)
	profileSelector := newImplementationProfileSelector(projectRoot, spec.Harness)
	accumulateBilledCost := func(report agent.ExecuteBeadReport) {
		costCap.Add(report.Harness, report.CostUSD)
	}
	costCapTripped := func() (work.StopDecision, agent.ExecuteBeadReport, bool) {
		if _, tripped := costCap.Tripped(); !tripped {
			return work.StopDecision{}, agent.ExecuteBeadReport{}, false
		}
		spent := costCap.Spent()
		decision, _ := work.ClassifyStop(work.StopInput{Budget: true})
		return decision, agent.ExecuteBeadReport{
			Status: agent.ExecuteBeadStatusExecutionFailed,
			Detail: fmt.Sprintf("cost cap reached: $%.2f billed >= $%.2f cap; raise the cap or set 0 to disable. Subscription and local providers do not count.", spent, spec.MaxCostUSD),
		}, true
	}

	singlePolicyAttempt := func(ctx context.Context, beadID string, requestedMinPower int, requestedProfile string, routingIntent escalation.ExecutionHint, routingNote string, resolvedHarness, resolvedProvider, resolvedModel string) (agent.ExecuteBeadReport, error) {
		gitOps := &agent.RealGitOps{}
		// Safety net: after the attempt returns, commit any execution-evidence
		// bundle that ExecuteBeadWithConfig published to the project root but the
		// land flow did not pick up — e.g. a terminal provider_connectivity /
		// route-failure that never produced a commit to land. Without this the
		// project worktree is left dirty after the tracker commit already landed
		// (ddx-ca94d157). Mirrors the server worker path
		// (internal/server/workers.go).
		var safetyNetAttemptID string
		defer func() {
			if safetyNetAttemptID != "" {
				_ = agent.VerifyCleanWorktree(projectRoot, safetyNetAttemptID)
			}
		}()
		attemptProvider := spec.Provider
		if resolvedProvider != "" {
			attemptProvider = resolvedProvider
		}
		reportFromResult := func(res *agent.ExecuteBeadResult) agent.ExecuteBeadReport {
			report := agent.ReportFromExecuteBeadResult(res, string(routingIntent.InferredPowerClass))
			applyExecutionRoutingIntentReport(&report, routingIntent, requestedProfile, routingNote)
			return report
		}
		loopOverrides := config.CLIOverrides{
			Harness:           resolvedHarness,
			Model:             resolvedModel,
			Provider:          attemptProvider,
			Profile:           requestedProfile,
			Effort:            spec.Effort,
			MinPower:          requestedMinPower,

			MinPower:          requestedMinPower,
			MaxPower:          spec.MaxPower,
			OpaquePassthrough: spec.OpaquePassthrough,
			AttemptBackend:    spec.AttemptBackend,
		}
		requestTimeout := spec.RequestTimeout.Duration
		if requestTimeout > 0 {
			loopOverrides.ProviderRequestTimeout = &requestTimeout
		}
		attemptRcfg, _ := config.LoadAndResolve(projectRoot, loopOverrides)
		res, execErr := agent.ExecuteBeadWithConfig(ctx, projectRoot, beadID, attemptRcfg, executeLoopAttemptRuntime(
			spec,
			cmd.OutOrStdout(),
			bead.NewStore(beadStoreRoot),
			f.AgentRunnerOverride,
			resourceChecker,
			beadStoreRoot,
		), gitOps)
		if res != nil {
			safetyNetAttemptID = res.AttemptID
		}
		if execErr != nil && res == nil {
			return agent.ExecuteBeadReport{}, execErr
		}
		if res != nil && agent.IsResourceExhaustedStatus(res.Status) {
			return reportFromResult(res), nil
		}
		if execErr != nil {
			agent.MarkResultExecutionError(res, execErr)
			return reportFromResult(res), nil
		}
		if res != nil && res.ResultRev != "" && res.ResultRev != res.BaseRev && res.ExitCode == 0 {
			targetBead, err := resolveAttemptBead(ctx, beadID, store, func() attemptBeadReader {
				if store == nil {
					return nil
				}
				return bead.NewStoreWithCollection(store.Dir, store.Collection)
			}, nil)
			if err != nil {
				return agent.ExecuteBeadReport{}, err
			}
			landRes, _, landErr := agent.SubmitWithPreMergeChecks(
				ctx, projectRoot, targetBead, res,
				func(req agent.LandRequest) (*agent.LandResult, error) { return localCoord.Submit(req) },
				bead.NewStore(beadStoreRoot),
				resolveClaimAssignee(), "ddx work",
				nil,
			)
			if landErr == nil {
				agent.ApplyLandResultToExecuteBeadResult(res, landRes)
				_ = agent.WriteExecuteBeadResultArtifact(projectRoot, res)
			} else {
				agent.MarkResultLandError(projectRoot, res, landErr)
				_ = agent.WriteExecuteBeadResultArtifact(projectRoot, res)
				return reportFromResult(res), nil
			}
		} else if res != nil && (res.Outcome == agent.ExecuteBeadOutcomeTaskFailed || res.ExitCode != 0) {
			if res.ResultRev != "" && res.ResultRev != res.BaseRev {
				res.Outcome = "preserved"
			} else {
				res.Outcome = "error"
			}
			res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
		} else if res != nil && res.ResultRev == res.BaseRev {
			res.Outcome = "no-changes"
			res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
		}
		return reportFromResult(res), nil
	}

	var ladderOnce sync.Once
	var ladder escalationFloorFinder
	loadLadder := func() escalationFloorFinder {
		ladderOnce.Do(func() {
			ladder = powerladder.NewLadder(nil)
			svc, svcErr := agent.ResolvePreflightServiceFromWorkDir(projectRoot)
			if svcErr != nil {
				return
			}
			modelFilter := agentlib.ModelFilter{}
			if spec.Harness != "" {
				modelFilter.Harness = spec.Harness
			}
			modelCtx, cancel := context.WithTimeout(cmd.Context(), 2*time.Second)
			defer cancel()
			models, listErr := svc.ListModels(modelCtx, modelFilter)
			if listErr != nil {
				return
			}
			ladder = powerladder.NewLadder(models)
		})
		return ladder
	}

	executor := f.tryExecutorOverride
	if executor == nil {
		executor = agent.ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (agent.ExecuteBeadReport, error) {
			targetBead, err := resolveAttemptBead(ctx, beadID, store, func() attemptBeadReader {
				if store == nil {
					return nil
				}
				return bead.NewStoreWithCollection(store.Dir, store.Collection)
			}, nil)
			if err != nil {
				return agent.ExecuteBeadReport{}, err
			}
			routingIntent := resolveCommandExecutionHint(ctx, targetBead, noRoutingFlags, hasProjectRoutingConfig)
			inferredPolicy := routingIntent.InferredPowerClass
			initialMinPower, unavailableReport, unavailable := investigationRetryInitialMinPower(targetBead, rcfg.MinPower(), spec.MaxPower, loadLadder())
			if unavailable {
				applyExecutionRoutingIntentReport(&unavailableReport, routingIntent, "", "")
				return unavailableReport, nil
			}
			if spec.Harness == "" && spec.Provider == "" && spec.Model == "" {
				if learnedMinPower, learnedUnavailableReport, learned := recentProviderConnectivityMinPower(store, time.Now().UTC(), initialMinPower, spec.MaxPower, loadLadder()); learned {
					if learnedUnavailableReport.Status != "" {
						learnedUnavailableReport.BeadID = beadID
						applyExecutionRoutingIntentReport(&learnedUnavailableReport, routingIntent, "", "")
						return learnedUnavailableReport, nil
					}
					if learnedMinPower > initialMinPower {
						initialMinPower = learnedMinPower
					}
				}
				// Pre-dispatch route-exclusion check: if every known route at
				// the requested floor is still inside the exclusion window,
				// skip this dispatch and let the retry policy raise MinPower
				// in memory for the next attempt.
				if svcForExcl, svcExclErr := agent.ResolvePreflightServiceFromWorkDir(projectRoot); svcExclErr == nil {
					if exclusionReport, skip := agent.CheckAndApplyRouteExclusions(
						ctx, svcForExcl, store, beadID, resolveClaimAssignee(),
						targetBead.Extra, time.Now().UTC(), initialMinPower,
						svcForExcl.ResolveRoute,
						func(p int) (int, error) { return nextEscalationFloor(loadLadder(), p) },
						spec.RouteResolutionTimeout.Duration,
						loopSessionID,
						time.Time{}, // lastActivityAt: caller lacks liveness snapshot; treat as stale → always count
					); skip {
						applyExecutionRoutingIntentReport(&exclusionReport, routingIntent, "", "")
						return exclusionReport, nil
					}
				}
			}
			initialProfile := spec.Profile
			initialRoutingNote := ""
			if spec.Harness != "" && spec.Model == "" && initialMinPower == 0 && spec.Profile != "" {
				if selection, selectErr := profileSelector.Select(ctx, escalation.PowerClass(spec.Profile), initialMinPower); selectErr == nil && selection.Name != "" {
					initialProfile = selection.Name
					initialRoutingNote = selection.Note
					if selection.MinPower > initialMinPower {
						initialMinPower = selection.MinPower
					}
					if spec.MaxPower > 0 && initialMinPower > 0 && initialMinPower >= spec.MaxPower {
						unavailableReport := routeUnavailableReport(targetBead, initialMinPower, spec.MaxPower, nil)
						applyExecutionRoutingIntentReport(&unavailableReport, routingIntent, initialProfile, initialRoutingNote)
						return unavailableReport, nil
					}
				}
			}
			if autoInferPowerClass {
				if selection, selectErr := profileSelector.Select(ctx, inferredPolicy, initialMinPower); selectErr == nil && selection.Name != "" {
					initialProfile = selection.Name
					initialRoutingNote = selection.Note
					if spec.MaxPower > 0 && initialMinPower > 0 && initialMinPower >= spec.MaxPower {
						unavailableReport := routeUnavailableReport(targetBead, initialMinPower, spec.MaxPower, nil)
						applyExecutionRoutingIntentReport(&unavailableReport, routingIntent, initialProfile, initialRoutingNote)
						return unavailableReport, nil
					}
				} else {
					var degradeNote string
					initialMinPower, unavailableReport, degradeNote, unavailable = zeroConfigInitialMinPower(targetBead, inferredPolicy, initialMinPower, spec.MaxPower, loadLadder())
					if unavailable {
						applyExecutionRoutingIntentReport(&unavailableReport, routingIntent, "", "")
						return unavailableReport, nil
					}
					if degradeNote != "" {
						initialRoutingNote = degradeNote
					}
				}
			}
			perBeadBudget := spec.MaxBeadCostUSD
			if override, ok := escalation.ParseBeadBudgetLabel(targetBead.Labels); ok {
				perBeadBudget = override
			}
			perBeadTracker := escalation.NewPerBeadCostTracker(perBeadBudget, harnessBilledLookup)
			report, err := runEscalatingPowerAttempts(
				ctx,
				initialMinPower,
				loadLadder(),
				func(ctx context.Context, requestedMinPower int) (agent.ExecuteBeadReport, error) {
					requestProfile := initialProfile
					routingNote := initialRoutingNote
					if autoInferPowerClass {
						if selection, selectErr := profileSelector.Select(ctx, inferredPolicy, requestedMinPower); selectErr == nil {
							// Empty selection means no no-extra-requirement policy covers this
							// retry floor. Drop the stale lower policy and send MinPower-only so
							// Fizeau can route or report no eligible candidate from live config.
							requestProfile = selection.Name
							if requestProfile == "" {
								routingNote = ""
							} else if selection.Note != "" {
								routingNote = selection.Note
							}
						}
					}
					return singlePolicyAttempt(ctx, beadID, requestedMinPower, requestProfile, routingIntent, routingNote, spec.Harness, spec.Provider, spec.Model)
				},
				nil,
				perBeadTracker,
				strings.TrimSpace(spec.Harness) == "" && strings.TrimSpace(spec.Provider) == "" && strings.TrimSpace(spec.Model) == "",
				agent.ProviderPin{Harness: spec.Harness, Provider: spec.Provider, Model: spec.Model},
			)
			if err == nil {
				accumulateBilledCost(report)
			}
			return report, err
		})
	}

	worker := &agent.ExecuteBeadWorker{
		Store:    workerStore,
		Reviewer: reviewer,
		EscalationNextFloor: func(actualPower int) (int, error) {
			return nextEscalationFloor(loadLadder(), actualPower)
		},
		Executor: executor,
	}

	cliLandingOps := agent.RealLandingGitOps{}
	progressLog := cmd.OutOrStdout()
	if jsonOutput {
		progressLog = io.Discard
	}
	result, err := worker.Run(cmd.Context(), rcfg, agent.ExecuteBeadLoopRuntime{
		Mode:                   spec.Mode,
		IdleInterval:           spec.IdleInterval.Duration,
		IgnoreCooldown:         spec.IgnoreCooldown,
		CooldownOverrideReason: spec.CooldownOverrideReason,
		Log:                    progressLog,
		CleanupLog:             cleanupLog,
		EventSink:              loopSink,
		WorkerID:               resolveClaimAssignee(),
		ProjectRoot:            projectRoot,
		CleanupRunner:          cleanupRunner,
		ResourceChecker:        resourceChecker,
		ServerHealthProbe:      serverHealthProbe,
		BinaryRefreshCheck:     f.buildWorkBinaryRefreshCheck(cmd, projectRoot, tryTargetBeadID, workSelfRefreshEnabled(cmd)),
		ProjectRootDirtyCheck:  agent.CanonicalRootDirtyPaths,
		SessionID:              loopSessionID,
		PreClaimHook:           buildCLIPreClaimHook(projectRoot, cliLandingOps),
		PreClaimIntakeHook:     intakeHook,
		PreClaimTimeout:        spec.PreClaimTimeout.Duration,
		RoutePreflight: func(ctx context.Context, harness, model string) error {
			if spec.Harness == "" {
				return nil
			}
			routeTimeout := spec.RouteResolutionTimeout.Duration
			if routeTimeout <= 0 {
				routeTimeout = agent.DefaultRouteResolutionTimeout
			}
			preflightCtx, cancel := context.WithTimeout(ctx, routeTimeout)
			defer cancel()
			if spec.Model != "" {
				return agent.ValidateForExecuteLoopViaService(preflightCtx, projectRoot, spec.Harness, spec.Model, spec.Provider)
			}
			return agent.ValidateHarnessOnlyRouteViaService(preflightCtx, projectRoot, spec.Harness, spec.Provider, spec.Profile, spec.MinPower, spec.MaxPower)
		},
		RouteResolutionTimeout:       spec.RouteResolutionTimeout.Duration,
		ClaimSuccessRateWindow:       optionalIntFlag(cmd, "claim-rate-window", agent.DefaultClaimSuccessRateWindow),
		ClaimSuccessRateThreshold:    optionalFloat64Flag(cmd, "claim-rate-threshold", agent.DefaultClaimSuccessRateThreshold),
		PreClaimWarnRepeatThreshold:  optionalIntFlag(cmd, "preclaim-warn-threshold", agent.DefaultPreClaimWarnRepeatThreshold),
		PreDispatchLintHook:          lintHook,
		PostAttemptTriageHook:        triageHook,
		ProseEvidenceHook:            proseHook,
		PostAttemptDecompositionHook: decompositionHook,
		BudgetStop:                   costCapTripped,
		NoReview:                     spec.NoReview,
		TargetBeadID:                 tryTargetBeadID,
		ReviewCostCap:                costCap,
		FinalizeDurableAudit:         f.buildAttemptAuditFinalizer(projectRoot, store),
		PostLadderExhaustionHook:     recoveryHook,
	})
	if err != nil && result != nil && (errors.Is(err, context.Canceled) || errors.Is(err, context.DeadlineExceeded)) {
		_ = writeExecuteLoopResult(cmd.OutOrStdout(), projectRoot, result, jsonOutput)
		if errors.Is(err, context.Canceled) {
			return NewExitError(130, "")
		}
	}
	if err != nil {
		return err
	}
	if result != nil && result.ExitReason == "binary_refresh" {
		return nil
	}
	return writeExecuteLoopResult(cmd.OutOrStdout(), projectRoot, result, jsonOutput)
}

func (f *CommandFactory) buildAttemptAuditFinalizer(projectRoot string, store *bead.Store) func(agent.ExecuteBeadReport) error {
	if f.durableAuditFinalizeOverride != nil {
		return f.durableAuditFinalizeOverride
	}
	return func(report agent.ExecuteBeadReport) error {
		return agent.FinalizeDurableAttemptAudit(projectRoot, store, report)
	}
}

func worktreeStillLive(meta agent.ExecutionCleanupMetadata, runStates []agent.RunState, now time.Time) bool {
	if meta.Preserved || meta.ActiveCandidateCycle || strings.TrimSpace(meta.CandidateRef) != "" {
		return true
	}
	if worktreeLivenessAlive(meta.Liveness, now) {
		return true
	}
	for _, state := range runStates {
		if !runStateMatchesWorktree(state, meta) {
			continue
		}
		if strings.TrimSpace(state.CandidateCyclePhase) != "" || strings.TrimSpace(state.CandidateRef) != "" {
			return true
		}
		if worktreeRunStateAlive(state, now) {
			return true
		}
	}
	return false
}

func worktreeLivenessAlive(liveness *agent.ExecutionCleanupLiveness, now time.Time) bool {
	if liveness == nil {
		return false
	}
	if processAlive(liveness.PID) {
		return true
	}
	if !liveness.ExpiresAt.IsZero() && now.Before(liveness.ExpiresAt) {
		return true
	}
	return !liveness.RefreshedAt.IsZero() && now.Sub(liveness.RefreshedAt) <= 2*time.Minute
}

