type backEdgeDecompositionStore struct {
	*bead.Store
	parentID string
}

func (s *backEdgeDecompositionStore) Create(ctx context.Context, b *bead.Bead) error {
	base := s.Store
	if err := base.Create(ctx, b); err != nil {
		return err
	}
	if b.Parent != s.parentID {
