// TestLoop_PreflightRejection_NoCooldown asserts ddx-5b3e57f4 AC #1: a
// routing preflight rejection is classified as Disrupted (operator config
// issue, not model failure). The bead must not be parked under any cooldown.
func TestLoop_PreflightRejection_NoCooldown(t *testing.T) {
	inner, candidate, _ := newExecuteLoopTestStore(t)
	store := &claimCountingStore{Store: inner}

	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(_ context.Context, beadID string) (ExecuteBeadReport, error) {
			t.Fatal("executor must not run on preflight rejection")
			return ExecuteBeadReport{}, nil
		}),
	}
	rejected := agentlib.ErrHarnessModelIncompatible{
		Harness: "claude", Model: "gpt-5", SupportedModels: []string{"claude-opus-4-7"},
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker", Harness: "claude", Model: "gpt-5"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
		Once: true,
		RoutePreflight: func(ctx context.Context, harness, model string) error {
			return rejected
		},
	})
	require.NoError(t, err)
	require.Len(t, result.Results, 1)

	report := result.Results[0]
	assert.True(t, report.Disrupted, "preflight rejection must be Disrupted")
	assert.Equal(t, "preflight_rejected", report.DisruptionReason)
	assert.Empty(t, report.RetryAfter,
		"preflight-rejected bead must not carry retry_after")

	got, err := inner.Get(context.Background(), candidate.ID)
	require.NoError(t, err)
	if got.Extra != nil {
		_, hasRetry := got.Extra["work-retry-after"]
		assert.False(t, hasRetry,
			"preflight-rejected bead must not have work-retry-after persisted")
	}
}

// TestLoop_DisruptionEventEmitted asserts ddx-5b3e57f4 AC #5: a
// `disruption_detected` event is appended to the bead and to the loop event
// sink when a Disrupted classification fires.
func TestLoop_DisruptionEventEmitted(t *testing.T) {
	store, candidate, _ := newExecuteLoopTestStore(t)

	transportErr := errors.New("dial tcp 127.0.0.1:443: connection refused")
	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(_ context.Context, id string) (ExecuteBeadReport, error) {
			return ExecuteBeadReport{
				BeadID:    id,
				Status:    ExecuteBeadStatusExecutionFailed,
				Detail:    transportErr.Error(),
				BaseRev:   "deadbeef",
				ResultRev: "deadbeef",
			}, transportErr
		}),
	}

	sink := &disruptionEventCapture{}
	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
		Once:      true,
		EventSink: sink,
		SessionID: "sess-disrupt",
	})
	require.NoError(t, err)
	require.NotNil(t, result)
	require.Len(t, result.Results, 1)

	report := result.Results[0]
	assert.True(t, report.Disrupted, "transport error must be classified Disrupted")

		go func() {
			<-ctx.Done()
			stopProcess()
		}()
	}

	// Wall-clock watchdog: fires at an absolute deadline regardless of
	// stream activity. Runs alongside the idle watchdog so a provider that
	// emits heartbeats cannot defeat the overall bound. See RC2 of
	// ddx-0a651925 for the incident that motivated this timer.
	wallClock := executionWallClockFromContext(ctx)
	if wallClock > 0 {
		wallClockStart := time.Now()
		go func() {
			timer := time.NewTimer(wallClock)
			defer timer.Stop()
			select {
			case <-ctx.Done():
				return
			case <-timer.C:
				wallClockTimedOut.Store(true)
				wallClockElapsed.Store(int64(time.Since(wallClockStart)))
				cancel()
				stopProcess()
			}
		}()
	}

	// Stream stdout to collect it and count any write as progress.
	stdoutDone := make(chan struct{})
	go func() {
		defer close(stdoutDone)
		_, _ = io.Copy(&activityWriter{Buffer: &stdoutBuf, OnWrite: pulse}, stdoutPipe)
	}()

	// Stream stderr: collect it, count progress, and watch for cancel patterns.
	stderrDone := make(chan struct{})
	go func() {
		defer close(stderrDone)
		scanner := bufio.NewScanner(stderrPipe)
		for scanner.Scan() {
			line := scanner.Text()
			stderrBuf.WriteString(line)
			stderrBuf.WriteByte('\n')
			pulse()
			if cancelReason == "" {
				if reason := matchesCancelPattern(line); reason != "" {
					cancelReason = reason
					cancel()
					stopProcess()
				}
			}
		}
		// Drain any remaining bytes not caught by the scanner.
		_, _ = io.Copy(&activityWriter{Buffer: &stderrBuf, OnWrite: pulse}, stderrPipe)
	}()

	<-stdoutDone
	<-stderrDone
	runErr := cmd.Wait()

	result := &ExecResult{
		Stdout:           stdoutBuf.String(),
		Stderr:           stderrBuf.String(),
		EarlyCancel:      cancelReason != "",
		CancelReason:     cancelReason,
		WallClockTimeout: wallClockTimedOut.Load(),
		WallClockElapsed: time.Duration(wallClockElapsed.Load()),
	}

	if runErr != nil {
		if cancelReason != "" {
			// We triggered the cancel; report as early-cancel rather than timeout.
			result.ExitCode = -1
			return result, nil
		}
		if wallClockTimedOut.Load() {
			result.ExitCode = -1
			return result, context.DeadlineExceeded
		}
		if timedOut.Load() {
			result.ExitCode = -1
			return result, context.DeadlineExceeded
		}
		if errors.Is(ctx.Err(), context.Canceled) || errors.Is(ctx.Err(), context.DeadlineExceeded) {
			result.ExitCode = -1
			return result, ctx.Err()
		}
		if exitErr, ok := runErr.(*exec.ExitError); ok {
			result.ExitCode = exitErr.ExitCode()
			return result, nil // non-zero exit is not an execution error
		}
		return result, runErr
	}
	return result, nil
}

func envWithOverrides(base []string, overrides map[string]string) []string {
	if len(base) == 0 && len(overrides) == 0 {
		return nil
	}
	if len(overrides) == 0 {
		return append([]string{}, base...)
	}

	skip := make(map[string]bool, len(overrides))
	keys := make([]string, 0, len(overrides))
	for key := range overrides {
		skip[key] = true
		keys = append(keys, key)
	}
	sort.Strings(keys)

	env := make([]string, 0, len(base)+len(overrides))
	for _, kv := range base {
		eq := strings.IndexByte(kv, '=')
		if eq < 0 {
			env = append(env, kv)
			continue
		}
		if skip[kv[:eq]] {
			continue
		}
		env = append(env, kv)
	}
	for _, key := range keys {
		env = append(env, key+"="+overrides[key])
	}
	return env
}

type activityWriter struct {
	Buffer  *bytes.Buffer
	OnWrite func()
}

func (w *activityWriter) Write(p []byte) (int, error) {
	if len(p) > 0 && w.OnWrite != nil {
		w.OnWrite()
	}
	return w.Buffer.Write(p)
}

