			}
		}
	}
}

res = &ExecuteBeadResult{
	BeadID:                      beadID,
	AttemptID:                   attemptID,
	WorkerID:                    runtime.WorkerID,
	BaseRev:                     baseRev,
	ResultRev:                   resultRev,
	Harness:                     resultHarness,
	Provider:                    resultProvider,
	Model:                       resultModel,
	ActualPower:                 actualPower,
	PredictedPower:              predictedPower,
	PredictedSpeedTPS:           predictedSpeedTPS,
	PredictedCostUSDPer1kTokens: predictedCostUSDPer1kTokens,
	PredictedCostSource:         predictedCostSource,
	SessionID:                   sessionID,
	DurationMS:                  int(finishedAt.Sub(startedAt).Milliseconds()),
	Tokens:                      tokens,
	CostUSD:                     costUSD,
	ExitCode:                    exitCode,
	Error:                       agentErrMsg,
	Stderr:                      agentStderr,
	RateLimitBudget:             runtime.RateLimitMaxWait,
	ProjectRoot:                 projectRoot,
	ExecutionDir:                artifacts.DirRel,
	PromptFile:                  artifacts.PromptRel,
	ManifestFile:                artifacts.ManifestRel,
	ResultFile:                  artifacts.ResultRel,
	UsageFile:                   usageFileRel,
	StartedAt:                   startedAt,
	FinishedAt:                  finishedAt,
}
if resultRev != baseRev {
	res.ImplementationRev = resultRev
}

// Classify worker outcome: task_succeeded / task_failed / task_no_changes /
// task_no_evidence. A clean agent exit with no commit is only a legitimate
// no_changes signal when the agent also wrote the explicit rationale file.
// If a rationale file appears alongside implementation commits, reject the
// mixed signal so the parent orchestrator does not see a clean success.
// The parent orchestrator (LandBeadResult + ApplyLandingToResult) will
// overwrite Outcome and Status with the landing decision before output.
agentReportedError := strings.TrimSpace(agentErrMsg) != ""
rationaleFile := filepath.Join(wtPath, artifacts.DirRel, "no_changes_rationale.txt")
rationaleText := ""
if data, readErr := os.ReadFile(rationaleFile); readErr == nil {
	rationaleText = strings.TrimSpace(string(data))
	if rationaleText != "" {
		res.NoChangesRationale = rationaleText
	}
}
mixedCommitAndRationale := resultRev != baseRev && rationaleText != ""
switch {
case mixedCommitAndRationale:
	res.Outcome = ExecuteBeadOutcomeTaskFailed
	res.Reason = mixedCommitAndNoChangesRationaleReason
	res.Error = mixedCommitAndNoChangesRationaleReason
case exitCode != 0 || agentReportedError:
	res.Outcome = ExecuteBeadOutcomeTaskFailed
case resultRev == baseRev:
	res.Outcome = ExecuteBeadOutcomeTaskNoChanges
default:
	res.Outcome = ExecuteBeadOutcomeTaskSucceeded
}

// When the outcome is no_changes, the agent's rationale file becomes the
// canonical explanation for the no-op decision. We read it before the
// deferred worktree cleanup removes the file.
if res.Outcome == ExecuteBeadOutcomeTaskNoChanges {
	if res.NoChangesRationale == "" {
		res.Outcome = ExecuteBeadOutcomeTaskNoEvidence
		res.Reason = "agent exited without a commit or no_changes_rationale.txt"
		paths := dirtyWorktreePaths(wtPath)
		res.NoEvidencePaths = paths
		if len(paths) > 0 {
			rescueRef := preserveDirtyNoEvidenceAttempt(wtPath, artifacts.DirAbs, artifacts.DirRel)
			if rescueRef != "" {
				res.PreserveRef = rescueRef
				res.Error = fmt.Sprintf("%s; dirty paths: %s; rescue: %s", res.Reason, strings.Join(paths, ", "), rescueRef)
			} else {
				res.Error = fmt.Sprintf("%s; dirty paths: %s", res.Reason, strings.Join(paths, ", "))
			}
		} else {
			res.Error = res.Reason
		}
	}
}

// Operator-cancel override (ADR-022 §Cancel SLA). When the mid-attempt
// poll detected cancel-requested:true on the bead, force the result into
// the preserved_for_review channel with reason "operator_cancel" so the
// orchestrator and supervisor surface it as an operator-driven preserve
// rather than a generic task_failed/no_evidence outcome.
if cancelHonored != nil && cancelHonored.Load() {
	res.Outcome = "preserved"
	res.Reason = OperatorCancelReason
	res.Error = ""
	res.ExitCode = 0
	res.FailureMode = ""
	res.Status = ExecuteBeadStatusPreservedNeedsReview
	res.Detail = ExecuteBeadStatusDetail(res.Status, OperatorCancelReason, "")
	_ = writeArtifactJSON(artifacts.ResultAbs, res)
	if err := publishAttemptResult(res); err != nil {
		return res, fmt.Errorf("publishing attempt result: %w", err)
	}
	return res, nil
}

// Classify failure mode from worker-level signals. ApplyLandingToResult
// may refine this with landing-level signals (merge conflict, gate
// failure) before the final result is output.
res.FailureMode = ClassifyFailureMode(res.Outcome, res.ExitCode, res.Error)

// Structured post-agent integrity validation (ddx-725b65b4). A clean agent
// exit with a commit is not sufficient evidence of a contract-honoring
// attempt: reject attempts that rewrote the implementation commit after the
// first commit, left required pre-commit gate evidence empty, or left tracked
// files uncommitted. Such attempts are demoted to task_failed with a distinct
// FailureMode so the orchestrator preserves them for review (rather than
// merging) and an operator can tell the DDx validation rejection apart from
// an implementation failure. The evidence-bundle commit (below) has not run
// yet, so the reflog only carries the agent's own commits.
if res.Outcome == ExecuteBeadOutcomeTaskSucceeded && res.ExitCode == 0 && res.ImplementationRev != "" {
	verdict := ValidateAttemptIntegrity(AttemptIntegrityInput{
		BaseRev:           baseRev,
		ImplementationRev: res.ImplementationRev,
		CommitEvents:      readWorktreeCommitEvents(wtPath),
		DirtyPaths:        integrityDirtyPaths(wtPath),

package agent

import (
	"errors"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/config"
)

const (
	ReadinessClassificationReady            = "ready"
	ReadinessClassificationNeedsRefine      = "needs_refine"
	ReadinessClassificationNeedsSplit       = "needs_split"
	ReadinessClassificationOperatorRequired = "operator_required"
	ReadinessClassificationSystemUnready    = "system_unready"

	ReadinessReasonTooLarge                       = "too_large"
	ReadinessReasonAmbiguousScope                 = "ambiguous_scope"
	ReadinessReasonMissingRootCauseOrCurrentState = "missing_root_cause_or_current_state"
	ReadinessReasonMissingVerification            = "missing_verification"
	ReadinessReasonMissingCodePathAssertion       = "missing_code_path_assertion"
	ReadinessReasonMissingDependencyOrParent      = "missing_dependency_or_parent"
	ReadinessReasonHiddenExternalBlocker          = "hidden_external_blocker"
	ReadinessReasonAlreadySatisfiedCandidate      = "already_satisfied_candidate"
	ReadinessReasonSystemUnready                  = "system_unready"

	ReadinessSystemReasonUnavailable       = "unavailable"
	ReadinessSystemReasonRouting           = "routing"
	ReadinessSystemReasonQuota             = "quota"
	ReadinessSystemReasonTransport         = "transport"
	ReadinessSystemReasonResourceExhausted = "resource_exhausted"
	ReadinessSystemReasonRepoConcurrency   = "repo_concurrency"
	ReadinessSystemReasonTimeout           = "timeout"
)

// ReadinessClassificationResult is the deterministic bridge between the
// bead-lifecycle readiness vocabulary and work scheduling semantics.
type ReadinessClassificationResult struct {
	Classification       string
	Reason               string
	SystemReason         string
	TriageClassification string
	IntakeOutcome        PreClaimIntakeOutcome
}

// ClassifyReadiness maps bead-lifecycle readiness evidence to a stable result.
// Infrastructure signals always win over bead-quality signals so routing,
// quota, transport, resource, and repository-concurrency failures do not park a
// bead as needs_refine/needs_split.
func ClassifyReadiness(classification string, reasons []string, detail string) ReadinessClassificationResult {
	return ClassifyReadinessWithMode(classification, reasons, detail, config.BeadQualityModeWarnOnly)
}

// ClassifyReadinessWithMode maps bead-lifecycle readiness evidence to a stable
// result using the configured bead-quality mode.
func ClassifyReadinessWithMode(classification string, reasons []string, detail, qualityMode string) ReadinessClassificationResult {
	classification = normalizeReadinessClassification(classification)
	reason := firstReadinessReason(reasons)
	systemReason := classifyReadinessSystemReason(detail, reasons)
	if classification == ReadinessClassificationSystemUnready ||
		reason == ReadinessReasonSystemUnready ||
		systemReason != "" {
		if systemReason == "" {
			systemReason = ReadinessSystemReasonUnavailable
		}
		return ReadinessClassificationResult{
			Classification:       ReadinessClassificationSystemUnready,
			Reason:               ReadinessReasonSystemUnready,
			SystemReason:         systemReason,
			TriageClassification: triageClassificationForSystemReason(systemReason),
			IntakeOutcome:        PreClaimIntakeError,
		}
	}

	if fromReason := readinessClassificationForReason(reason); fromReason != "" {
		classification = fromReason
	}
	if classification == "" {
		classification = ReadinessClassificationReady
	}

	out := ReadinessClassificationResult{
		Classification: classification,
		Reason:         reason,
	}
	switch classification {
	case ReadinessClassificationReady:
		out.IntakeOutcome = PreClaimIntakeActionableAtomic
	case ReadinessClassificationNeedsSplit:
		if out.Reason == "" {
			out.Reason = ReadinessReasonTooLarge
		}
		out.IntakeOutcome = PreClaimIntakeTooLargeDecomposed
	case ReadinessClassificationOperatorRequired:
		if out.Reason == "" {
			out.Reason = ReadinessReasonAmbiguousScope
		}
		out.IntakeOutcome = PreClaimIntakeOperatorRequired
	case ReadinessClassificationNeedsRefine:
		if isReadinessBlockingMode(qualityMode) {
			// In BLOCK/factory mode, a refinement need still parks the bead.
			out.IntakeOutcome = PreClaimIntakeOperatorRequired
		} else {
			// WARN-ONLY mode reports the finding but still proceeds.
			out.IntakeOutcome = PreClaimIntakeActionableAtomic
		}
	default:
		out.Classification = ReadinessClassificationSystemUnready
		out.Reason = ReadinessReasonSystemUnready
		out.SystemReason = ReadinessSystemReasonUnavailable
		out.TriageClassification = triageClassificationForSystemReason(out.SystemReason)
		out.IntakeOutcome = PreClaimIntakeError
	}
	return out
}

func isReadinessBlockingMode(mode string) bool {
	switch strings.ToLower(strings.TrimSpace(mode)) {
	case config.BeadQualityModeBlock, "factory":
		return true
	default:
		return false
	}
}

func normalizeReadinessClassification(classification string) string {
	switch strings.ToLower(strings.TrimSpace(classification)) {
	case "", "ready", "actionable_atomic", "atomic", "ok", "actionable", "pass":
		return ReadinessClassificationReady
	case "needs_refine", "actionable_but_rewritten", "rewritten", "safely_refinable":
		return ReadinessClassificationNeedsRefine
	case "needs_split", "too_large", "too_large_decomposed", "decomposable", "split":
		return ReadinessClassificationNeedsSplit
	case "operator_required", "human_review_required", "ambiguous":
		return ReadinessClassificationOperatorRequired
	case "system_unready", "readiness_error", "intake_error":
		return ReadinessClassificationSystemUnready
	default:
		return strings.ToLower(strings.TrimSpace(classification))
	}
}

func normalizeReadinessReason(reason string) string {
	switch strings.ToLower(strings.TrimSpace(reason)) {
	case ReadinessReasonTooLarge,
		ReadinessReasonAmbiguousScope,
		ReadinessReasonMissingRootCauseOrCurrentState,
		ReadinessReasonMissingVerification,
		ReadinessReasonMissingCodePathAssertion,
		ReadinessReasonMissingDependencyOrParent,
		ReadinessReasonHiddenExternalBlocker,
		ReadinessReasonAlreadySatisfiedCandidate,
		ReadinessReasonSystemUnready:
		return strings.ToLower(strings.TrimSpace(reason))
	default:
		return strings.ToLower(strings.TrimSpace(reason))
	}
}

func firstReadinessReason(reasons []string) string {
	for _, reason := range reasons {
		reason = normalizeReadinessReason(reason)
		if reason != "" {
			return reason
		}
	}
	return ""
}

func readinessClassificationForReason(reason string) string {
	switch normalizeReadinessReason(reason) {
	case ReadinessReasonTooLarge:
		return ReadinessClassificationNeedsSplit
	case ReadinessReasonAmbiguousScope, ReadinessReasonHiddenExternalBlocker:
		return ReadinessClassificationOperatorRequired
	case ReadinessReasonMissingRootCauseOrCurrentState,
		ReadinessReasonMissingVerification,
		ReadinessReasonMissingCodePathAssertion,
		ReadinessReasonMissingDependencyOrParent,
		ReadinessReasonAlreadySatisfiedCandidate:
		return ReadinessClassificationNeedsRefine
	case ReadinessReasonSystemUnready:
		return ReadinessClassificationSystemUnready
	default:
		return ""
	}
}

